type HektorNegotiatorRequiredDossier = Pick<Dossier, 'app_dossier_id' | 'hektor_annonce_id'> & Partial<Pick<Dossier, 'numero_dossier' | 'numero_mandat' | 'titre_bien' | 'ville' | 'commercial_id' | 'commercial_nom' | 'agence_nom' | 'negociateur_email'>>
type MissingNegotiatorHandler = (dossier: HektorNegotiatorRequiredDossier) => void

function hasHektorNegotiator(dossier: HektorNegotiatorRequiredDossier) {
  return Boolean(String(dossier.commercial_id ?? '').trim() || String(dossier.negociateur_email ?? '').trim())
}

const allFilterValue = '__all__'
const activeArchiveFilterValue = '__active__'
const archivedFilterValue = '__archived__'
const withMandatFilterValue = '__with_mandat__'
const withoutMandatFilterValue = '__without_mandat__'
const withoutCommercialFilterValue = '__without_commercial__'
const activeListingsFilterValue = '__active_listings__'
const annonceSearchListingsFilterValue = '__annonce_search_listings__'
const detailAvailableFilterValue = 'available'
const detailToLoadFilterValue = 'to_load'
const activeContactSearchFilterValue = '__active_search__'
const withContactSearchFilterValue = '__with_search__'
const withoutContactSearchFilterValue = '__without_search__'
const activeListingsFilterOption = { value: activeListingsFilterValue, label: 'Actif / offre / compromis' }
const historicalListingStatusOptions = [
  { value: 'Vendu', label: 'Vendu' },
  { value: 'Clos', label: 'Clos' },
]
const heavyListingFilterKeys = new Set<keyof AppFilters>([
  'validationDiffusion',
  'diffusable',
  'passerelle',
  'erreurDiffusion',
  'priority',
  'workStatus',
  'internalStatus',
  'requestType',
  'requestScope',
  'affaire',
  'offreStatus',
  'compromisStatus',
])
type Screen = 'annonces' | 'mandats' | 'estimations' | 'registre' | 'contacts' | 'suivi'
type BusinessRequestType = 'demande_diffusion' | 'demande_baisse_prix' | 'demande_annulation_mandat'
type LightweightDetailTarget = Dossier | MandatRecord

function isHistoricalListingStatus(value: unknown) {
  return value === 'Vendu' || value === 'Clos'
}

function usesLightweightAnnonceIndex(filters: AppFilters) {
  return (
    filters.archive === allFilterValue ||
    filters.archive === archivedFilterValue ||
    filters.statut === annonceSearchListingsFilterValue ||
    isHistoricalListingStatus(filters.statut) ||
    (filters.archive === activeArchiveFilterValue && filters.statut === allFilterValue)
  )
}

type AnnonceSearchScope = 'current' | 'extended'

function applyAnnonceSearchDefaultScope(screen: Screen, filters: AppFilters, searchScope: AnnonceSearchScope): AppFilters {
  void screen
  void searchScope
  return filters
}

function annonceSearchScopeText(filters: AppFilters) {
  if (filters.statut === annonceSearchListingsFilterValue) return 'toutes les annonces hors estimations'
  if (filters.archive === archivedFilterValue) return 'les archives'
  if (filters.statut === 'Vendu') return 'les annonces vendues'
  if (filters.statut === 'Clos') return 'les annonces closes'
  if (filters.archive === allFilterValue) return 'toutes les annonces hors estimations'
  if (filters.archive === activeArchiveFilterValue && filters.statut === activeListingsFilterValue) return 'les annonces actives / offres / compromis'
  if (filters.archive === activeArchiveFilterValue && filters.statut === allFilterValue) return 'les annonces actives, vendues et closes'
  if (filters.statut && filters.statut !== allFilterValue) return `les annonces ${filters.statut.toLowerCase()}`
  return 'les annonces correspondant aux filtres'
}

function annonceSearchExtendLabel(filters: AppFilters) {
  if (filters.archive === archivedFilterValue) return 'Chercher aussi dans les actives, vendues et closes'
  if (filters.statut === 'Vendu') return 'Chercher aussi dans les actives, closes et archives'
  if (filters.statut === 'Clos') return 'Chercher aussi dans les actives, vendues et archives'
  return 'Etendre aux archives, vendus et clos'
}

function extendAnnonceSearchFilters(filters: AppFilters): AppFilters {
  return {
    ...filters,
    archive: allFilterValue,
    statut: allFilterValue,
  }
}

function resetAnnonceSearchScopeFilters(filters: AppFilters): AppFilters {
  return {
    ...filters,
    archive: activeArchiveFilterValue,
    statut: activeListingsFilterValue,
  }
}

function isLightweightAnnonceRecord(item: Pick<Dossier, 'archive' | 'statut_annonce'> | Pick<MandatRecord, 'archive' | 'statut_annonce'> | null | undefined) {
  if (!item) return false
  return item.archive === '1' || isHistoricalListingStatus(item.statut_annonce)
}

function isArchivedAnnonceRecord(item: Pick<Dossier, 'archive'> | Pick<MandatRecord, 'archive'> | null | undefined) {
  return item?.archive === '1'
}

function isHistoricalLightweightRecord(item: Pick<Dossier, 'archive' | 'statut_annonce'> | Pick<MandatRecord, 'archive' | 'statut_annonce'> | null | undefined) {
  return Boolean(item && item.archive !== '1' && isHistoricalListingStatus(item.statut_annonce))
}

function hasLocalDetailAvailable(item: Pick<Dossier, 'has_local_detail'> | Pick<MandatRecord, 'has_local_detail'> | null | undefined) {
  return item?.has_local_detail === true || item?.has_local_detail === 1 || item?.has_local_detail === '1'
}

function hasDetailCacheAvailable(item: Pick<Dossier, 'has_detail_cache'> | Pick<MandatRecord, 'has_detail_cache'> | null | undefined) {
  return item?.has_detail_cache === true || item?.has_detail_cache === 1 || item?.has_detail_cache === '1'
}

function isReadOnlyLightweightDetail(item: Pick<Dossier, 'archive' | 'statut_annonce' | 'has_detail_cache'> | Pick<MandatRecord, 'archive' | 'statut_annonce' | 'has_detail_cache'> | null | undefined) {
  if (!item) return false
  if (item.archive === '1') return true
  return isHistoricalListingStatus(item.statut_annonce) && !hasDetailCacheAvailable(item)
}

function annonceListingLabels(filters: AppFilters) {
  if (filters.archive === archivedFilterValue) {
    return { title: 'Archives', totalNoun: 'annonces archivees' }
  }
  if (filters.statut === annonceSearchListingsFilterValue) {
    return { title: 'Recherche annonces', totalNoun: 'annonces' }
  }
  if (filters.statut === 'Vendu') {
    return { title: 'Annonces vendues', totalNoun: 'annonces vendues' }
  }
  if (filters.statut === 'Clos') {
    return { title: 'Annonces closes', totalNoun: 'annonces closes' }
  }
  return { title: 'Annonces actives', totalNoun: 'annonces actives' }
}

function clearHeavyListingFilters(next: AppFilters) {
  next.validationDiffusion = allFilterValue
  next.diffusable = allFilterValue
  next.passerelle = allFilterValue
  next.erreurDiffusion = allFilterValue
  next.priority = allFilterValue
  next.workStatus = allFilterValue
  next.internalStatus = allFilterValue
  next.requestType = allFilterValue
  next.requestScope = allFilterValue
  next.affaire = allFilterValue
  next.offreStatus = allFilterValue
  next.compromisStatus = allFilterValue
}

function numericDraft(value: unknown): string {
  return String(value ?? '').replace(/[^\d,.-]/g, '').trim()
}

