function rawDetailProp(detail: DossierDetailPayload, group: string, key: string) {
  const raw = parseJson<Record<string, unknown>>(detail.detail_raw_json, {})
  const groupValue = raw[group] as { props?: Record<string, { value?: unknown }> } | undefined
  const value = groupValue?.props?.[key]?.value
  return value == null ? '' : String(value)
}

function rawDetailFirstProp(detail: DossierDetailPayload, group: string, keys: string[]) {
  for (const key of keys) {
    const value = rawDetailProp(detail, group, key)
    if (value) return value
  }
  return ''
}

const hektorWizardRawDetailGroups = [
  'mandat_infofi',
  'mandat_mandatdispo',
  'secteur',
  'ag_interieur',
  'ag_exterieur',
  'terrain',
  'equipements',
  'diagnostiques',
  'copropriete',
  'organiser_visite',
]

function wizardFieldRawCandidates(name: string) {
  const candidates = [name]
  if (name.endsWith('-')) candidates.push(name.slice(0, -1))
  else candidates.push(`${name}-`)
  return candidates
}

function rawWizardDetailField(detail: DossierDetailPayload, name: string) {
  const candidates = wizardFieldRawCandidates(name)
  for (const group of hektorWizardRawDetailGroups) {
    const value = rawDetailFirstProp(detail, group, candidates)
    if (value) return value
  }
  return ''
}

function wizardDetailValue(
  dossier: Pick<Dossier, 'titre_bien' | 'prix' | 'numero_dossier' | 'diffusable'>,
  detail: DossierDetailPayload,
  field: DraftAnnonceWizardField,
) {
  const name = field.name
  const mapped: Record<string, unknown> = {
    titre: firstNonEmpty(detail.texte_principal_titre, dossier.titre_bien),
    corps: firstNonEmpty(detail.texte_principal_html, detail.corps_listing_html),
    prix: firstNonEmpty(detail.prix_publique, dossier.prix),
    PRIXNETVENDEUR: detail.prix_net_vendeur,
    surfappart: firstNonEmpty(detail.surface_habitable_detail, detail.surface),
    surfterrain: detail.surface_terrain_detail,
    nbpieces: detail.nb_pieces,
    NB_CHAMBRES: detail.nb_chambres,
    codepublique: firstNonEmpty(detail.code_postal_public_listing, detail.code_postal_detail, detail.code_postal),
    villepublique: firstNonEmpty(detail.ville_publique_listing, detail.ville_privee_detail),
    ADRESSE_COMPL: firstNonEmpty(detail.adresse_privee_listing, detail.adresse_detail),
    latitude: detail.latitude_detail,
    longitude: detail.longitude_detail,
    NO_DOSSIER: firstNonEmpty(dossier.numero_dossier, rawDetailProp(detail, 'mandat_mandatdispo', 'NO_DOSSIER')),
    dateenr: firstNonEmpty(detail.date_enregistrement_annonce, rawDetailProp(detail, 'mandat_mandatdispo', 'dateenr')),
    diffusable: isDiffusableValue(firstNonEmpty(detail.diffusable, dossier.diffusable)) ? '1' : '0',
  }
  const direct = mapped[name]
  if (direct != null && String(direct).trim()) return String(direct).trim()
  const raw = rawWizardDetailField(detail, name)
  if (raw) return raw
  return field.defaultValue ?? ''
}

type HektorWizardDetailGroup = Omit<DraftAnnonceWizardGroup, 'fields'> & {
  fields: Array<DraftAnnonceWizardField & { value: string }>
}

function buildHektorWizardDetailGroups(
  dossier: Pick<Dossier, 'titre_bien' | 'prix' | 'numero_dossier' | 'diffusable' | 'type_bien'>,
  detail: DossierDetailPayload,
): HektorWizardDetailGroup[] {
  const profileKind = hektorPropertyProfileKindForDetail(dossier, detail)
  return filterDraftAnnonceWizardGroupsForProfile(draftAnnonceWizardGroups, profileKind).map((group) => ({
    ...group,
    fields: group.fields.map((field) => ({
      ...field,
      value: wizardDetailValue(dossier, detail, field),
    })),
  }))
}

function buildHektorWizardUpdateDraft(
  dossier: Pick<Dossier, 'titre_bien' | 'prix' | 'numero_dossier' | 'diffusable' | 'type_bien'>,
  detail: DossierDetailPayload,
) {
  return Object.fromEntries(
    buildHektorWizardDetailGroups(dossier, detail)
      .flatMap((group) => group.fields.map((field) => [field.name, field.value])),
  ) as Record<string, string>
}

function wizardDisplayValue(field: DraftAnnonceWizardField, value: string) {
  const clean = String(value ?? '').trim()
  if (!clean) return '-'
  const option = field.options?.find((item) => item.value === clean)
  return option?.label ?? clean
}

function hektorPropertyProfileKindForDetail(
  dossier: Pick<Dossier, 'type_bien'>,
  detail: DossierDetailPayload,
): HektorPropertyProfileKind {
  const rawTypeId = rawDetailProp(detail, 'offre_type', 'idtype')
  if (rawTypeId) return draftAnnoncePropertyProfileKindForTypeId(rawTypeId)
  return draftAnnoncePropertyProfileKindFromText(dossier.type_bien)
}

function buildHektorAdvancedDraft(dossier: Pick<Dossier, 'titre_bien' | 'prix' | 'numero_mandat'>, detail: DossierDetailPayload) {
  return {
    title: dossier.titre_bien ?? '',
    description: '',
    address: firstNonEmpty(detail.adresse_privee_listing, detail.adresse_detail),
    postalCode: firstNonEmpty(detail.code_postal_public_listing, detail.code_postal_prive_detail, detail.code_postal_detail, detail.code_postal),
    city: firstNonEmpty(detail.ville_publique_listing, detail.ville_privee_detail),
    building: rawDetailFirstProp(detail, 'secteur', ['immeuble', 'IMMEUBLE']),
    transport: rawDetailFirstProp(detail, 'secteur', ['TRANSPORT', 'transport']),
    proximity: rawDetailFirstProp(detail, 'secteur', ['PROXIMITE', 'proximite']),
    environment: rawDetailFirstProp(detail, 'secteur', ['ENVIRONNEMENT', 'environnement']),
    latitude: numericDraft(detail.latitude_detail ?? rawDetailProp(detail, 'secteur', 'latitude')),
    longitude: numericDraft(detail.longitude_detail ?? rawDetailProp(detail, 'secteur', 'longitude')),
    price: numericDraft(dossier.prix),
    surface: numericDraft(detail.surface_habitable_detail ?? detail.surface),
    roomCount: numericDraft(detail.nb_pieces),
    bedroomCount: numericDraft(detail.nb_chambres),
    bathroomCount: rawDetailFirstProp(detail, 'ag_interieur', ['NB_SDB', 'SDB']),
    showerRoomCount: rawDetailFirstProp(detail, 'ag_interieur', ['NB_SE', 'SE', 'SDE']),
    wcCount: rawDetailFirstProp(detail, 'ag_interieur', ['NB_WC', 'WC']),
    kitchen: rawDetailProp(detail, 'ag_interieur', 'CUISINE'),
    exposure: rawDetailProp(detail, 'ag_interieur', 'EXPOSITION'),
    view: rawDetailProp(detail, 'ag_interieur', 'vuee'),
    interiorState: rawDetailFirstProp(detail, 'diagnostiques', ['etat_interieur', 'ETAT_INTERIEUR']),
    exteriorState: rawDetailFirstProp(detail, 'diagnostiques', ['etat_exterieur', 'ETAT_EXTERIEUR']),
    landSurface: numericDraft(detail.surface_terrain_detail || rawDetailProp(detail, 'terrain', 'surfterrain')),
    gardenSurface: rawDetailProp(detail, 'ag_exterieur', 'SURFACE_JARDIN'),
    terraceCount: rawDetailFirstProp(detail, 'ag_exterieur', ['NB_TERRASSE', 'TERRASSE']),
    garageCount: rawDetailProp(detail, 'ag_exterieur', 'GARAGE_BOX'),
    garageSurface: rawDetailProp(detail, 'ag_exterieur', 'SURFACE_GARAGE'),
    parkingInsideCount: rawDetailProp(detail, 'ag_exterieur', 'NB_PARK_INT'),
    parkingOutsideCount: rawDetailProp(detail, 'ag_exterieur', 'NB_PARK_EXT'),
    pool: rawDetailProp(detail, 'ag_exterieur', 'PISCINE'),
    dpeValue: rawDetailFirstProp(detail, 'diagnostiques', ['dpe_cons', 'DPE']),
    gesValue: rawDetailFirstProp(detail, 'diagnostiques', ['dpe_ges', 'GES']),
    constructionYear: rawDetailFirstProp(detail, 'diagnostiques', ['ANNEE_CONS', 'ANNEE_CONSTRUCTION']),
    diagnosticRiskComment: rawDetailProp(detail, 'diagnostiques', 'diag_risques_nat_tech_commentaire'),
    coproLots: rawDetailProp(detail, 'copropriete', 'copropriete_nb_lot'),
    coproCharges: rawDetailProp(detail, 'mandat_infofi', 'CHARGES'),
    coproQuotePart: rawDetailProp(detail, 'copropriete', 'copropriete_quote_part'),
    coproWorksFund: rawDetailProp(detail, 'copropriete', 'montant_fonds_travaux'),
    mandateNumber: dossier.numero_mandat == null ? '' : String(dossier.numero_mandat),
    mandateType: '',
    mandateStartDate: '',
    mandateEndDate: '',
    netSellerPrice: rawDetailProp(detail, 'mandat_infofi', 'PRIXNETVENDEUR'),
    fees: '',
  } satisfies Record<HektorAdvancedFieldKey, string>
}

const hektorFinancialFieldKeys = new Set<HektorAdvancedFieldKey>([
  'price',
  'netSellerPrice',
  'coproCharges',
  'fees',
])

const hektorUnsupportedDirectUpdateWizardFields = new Set(['diffusable'])

function HektorCompositionPiecesEditor(props: {
  title: string
  subtitle?: string
  pieces: HektorCompositionPieceDraft[]
  draft: HektorCompositionPieceDraft
  disabled?: boolean
  className?: string
  onDraftChange: (key: HektorCompositionPieceDraftKey, value: string) => void
  onAddDraft: () => void
  onPieceChange: (localId: string, key: HektorCompositionPieceDraftKey, value: string) => void
  onRemovePiece: (localId: string) => void
  onRestorePiece?: (localId: string) => void
}) {
  const activePieces = props.pieces.filter((piece) => !piece.deleted)
  const deletedPieces = props.pieces.filter((piece) => piece.deleted)
  const renderPieceFields = (piece: HektorCompositionPieceDraft, prefix: string, onChange: (key: HektorCompositionPieceDraftKey, value: string) => void) => (
    <>
      <label className="filter-field">
        <span>Type de piece</span>
        <select
          value={piece.idTypePiece}
          onChange={(event) => onChange('idTypePiece', event.target.value)}
          disabled={props.disabled}
        >
          {hektorCompositionPieceTypeOptions.map((option) => (
            <option key={`${prefix}-type-${option.value}`} value={option.value}>{option.label}</option>
          ))}
        </select>
      </label>
      <label className="filter-field">
        <span>Detail</span>
        <input value={piece.detailPiece} onChange={(event) => onChange('detailPiece', event.target.value)} disabled={props.disabled} placeholder="Ex : suite parentale" />
      </label>
      <label className="filter-field is-small">
        <span>Etage</span>
        <input value={piece.etagePiece} onChange={(event) => onChange('etagePiece', event.target.value)} disabled={props.disabled} inputMode="numeric" placeholder="0" />
      </label>
      <label className="filter-field is-small">
        <span>Surface</span>
        <input value={piece.surfacePiece} onChange={(event) => onChange('surfacePiece', event.target.value)} disabled={props.disabled} inputMode="decimal" placeholder="m2" />
      </label>
      <label className="filter-field hektor-composition-note">
        <span>Note publique</span>
        <textarea value={piece.notePublique} onChange={(event) => onChange('notePublique', event.target.value)} disabled={props.disabled} placeholder="Visible dans Hektor" />
      </label>
      <label className="filter-field hektor-composition-note">
        <span>Note privee</span>
        <textarea value={piece.notePrivee} onChange={(event) => onChange('notePrivee', event.target.value)} disabled={props.disabled} placeholder="Interne" />
      </label>
      <label className="filter-field hektor-composition-note">
        <span>Note inter-agence</span>
        <textarea value={piece.noteInterAgence} onChange={(event) => onChange('noteInterAgence', event.target.value)} disabled={props.disabled} placeholder="Inter-agence" />
      </label>
    </>
  )

  return (
    <section className={`hektor-composition-editor ${props.className ?? ''}`}>
      <div className="draft-annonce-section-title hektor-composition-title">
        <span>Page 4</span>
        <strong>{props.title}</strong>
      </div>
      {props.subtitle ? <p className="hektor-composition-subtitle">{props.subtitle}</p> : null}
      <div className="hektor-composition-draft">
        <div className="hektor-composition-draft-head">
          <strong>Ajouter une piece</strong>
          <span>{activePieces.length} piece(s) preparee(s)</span>
        </div>
        <div className="hektor-composition-grid">
          {renderPieceFields(props.draft, 'draft-composition-piece', props.onDraftChange)}
        </div>
        <div className="hektor-composition-actions">
          <button className="ghost-button button-primary" type="button" onClick={props.onAddDraft} disabled={props.disabled || !hektorCompositionPieceHasContent(props.draft)}>Ajouter la piece</button>
        </div>
      </div>
      <div className="hektor-composition-list">
        {activePieces.length ? activePieces.map((piece, index) => (
          <article key={piece.localId} className="hektor-composition-card">
            <div className="hektor-composition-card-head">
              <span>{index + 1}</span>
              <strong>{hektorCompositionPieceDisplayTitle(piece)}</strong>
              <button className="ghost-button button-subtle" type="button" onClick={() => props.onRemovePiece(piece.localId)} disabled={props.disabled}>
                Supprimer
              </button>
            </div>
            <div className="hektor-composition-grid">
              {renderPieceFields(piece, piece.localId, (key, value) => props.onPieceChange(piece.localId, key, value))}
            </div>
          </article>
        )) : (
          <p className="hektor-composition-empty">Aucune piece ajoutee. Ajoute les pieces une par une comme dans Hektor.</p>
        )}
        {deletedPieces.length ? (
          <div className="hektor-composition-deleted">
            {deletedPieces.map((piece) => (
              <button key={`deleted-${piece.localId}`} type="button" onClick={() => props.onRestorePiece?.(piece.localId)} disabled={props.disabled || !props.onRestorePiece}>
                Restaurer {hektorCompositionPieceDisplayTitle(piece)}
              </button>
            ))}
          </div>
        ) : null}
      </div>
    </section>
  )
}

function HektorAnnonceUpdateForm(props: {
  dossier: Pick<Dossier, 'app_dossier_id' | 'hektor_annonce_id' | 'titre_bien' | 'prix' | 'numero_dossier' | 'numero_mandat' | 'negociateur_email' | 'type_bien' | 'diffusable'>
  detail: DossierDetailPayload
  compact?: boolean
  fieldPanel?: boolean
  onCancel?: () => void
  onJobCreated?: (job: ConsoleJob) => void
  onMissingNegotiator?: MissingNegotiatorHandler
}) {
  const { dossier, detail } = props
  const [values, setValues] = useState<Record<string, string>>(() => buildHektorWizardUpdateDraft(dossier, detail))
  const [compositionPieces, setCompositionPieces] = useState<HektorCompositionPieceDraft[]>(() => buildHektorCompositionPiecesFromDetail(detail))
  const [compositionDraft, setCompositionDraft] = useState<HektorCompositionPieceDraft>(() => createEmptyHektorCompositionPieceDraft())
  const [pending, setPending] = useState(false)
  const [message, setMessage] = useState<string | null>(null)
  const [error, setError] = useState<string | null>(null)
  const profileKind = hektorPropertyProfileKindForDetail(dossier, detail)
  const visibleSections = filterDraftAnnonceWizardGroupsForProfile(draftAnnonceWizardGroups, profileKind)
    .map((section) => ({
      ...section,
      fields: section.fields.filter((field) => !hektorUnsupportedDirectUpdateWizardFields.has(field.name)),
    }))
    .filter((section) => section.fields.length > 0)
  const visibleFieldNames = new Set(visibleSections.flatMap((section) => section.fields.map((field) => field.name)))
  const sectionsBeforeComposition = visibleSections.filter((section) => section.step < 4)
  const sectionsAfterComposition = visibleSections.filter((section) => section.step > 4)

  useEffect(() => {
    setValues(buildHektorWizardUpdateDraft(dossier, detail))
    setCompositionPieces(buildHektorCompositionPiecesFromDetail(detail))
    setCompositionDraft(createEmptyHektorCompositionPieceDraft())
    setMessage(null)
    setError(null)
    setPending(false)
  }, [dossier.app_dossier_id, dossier.titre_bien, dossier.prix, dossier.numero_dossier, dossier.numero_mandat, dossier.diffusable, dossier.type_bien, detail.detail_raw_json, detail.pieces_json, detail.texte_principal_titre, detail.texte_principal_html, detail.corps_listing_html, detail.adresse_privee_listing, detail.adresse_detail, detail.code_postal_public_listing, detail.code_postal_prive_detail, detail.code_postal_detail, detail.code_postal, detail.ville_publique_listing, detail.ville_privee_detail, detail.latitude_detail, detail.longitude_detail, detail.surface_habitable_detail, detail.surface, detail.nb_pieces, detail.nb_chambres, detail.diffusable])

  const updateField = (name: string, value: string) => {
    setValues((current) => ({ ...current, [name]: value }))
  }

  const updateCompositionDraft = (key: HektorCompositionPieceDraftKey, value: string) => {
    setCompositionDraft((current) => ({
      ...current,
      [key]: value,
      typeLabel: key === 'idTypePiece' ? hektorCompositionPieceTypeLabel(value) : current.typeLabel,
    }))
  }

  const addCompositionDraft = () => {
    if (!hektorCompositionPieceHasContent(compositionDraft)) {
      setError('Ajoute au moins un type, une surface ou un detail pour la piece.')
      return
    }
    setCompositionPieces((current) => [...current, createEmptyHektorCompositionPieceDraft({
      ...compositionDraft,
      localId: '',
      typeLabel: compositionDraft.typeLabel || hektorCompositionPieceTypeLabel(compositionDraft.idTypePiece),
    })])
    setCompositionDraft(createEmptyHektorCompositionPieceDraft())
    setError(null)
  }

  const updateCompositionPiece = (localId: string, key: HektorCompositionPieceDraftKey, value: string) => {
    setCompositionPieces((current) => current.map((piece) => piece.localId === localId ? {
      ...piece,
      [key]: value,
      typeLabel: key === 'idTypePiece' ? hektorCompositionPieceTypeLabel(value) : piece.typeLabel,
    } : piece))
  }

  const removeCompositionPiece = (localId: string) => {
    setCompositionPieces((current) => current.flatMap((piece) => {
      if (piece.localId !== localId) return [piece]
      return piece.idPiece ? [{ ...piece, deleted: true }] : []
    }))
  }

  const restoreCompositionPiece = (localId: string) => {
    setCompositionPieces((current) => current.map((piece) => piece.localId === localId ? { ...piece, deleted: false } : piece))
  }

  const handleSubmit = async (event: FormEvent<HTMLFormElement>) => {
    event.preventDefault()
    setMessage(null)
    setError(null)
    if (!hasHektorNegotiator(dossier)) {
      props.onMissingNegotiator?.(dossier)
      return
    }
    const baseline = buildHektorWizardUpdateDraft(dossier, detail)
    const changedValues = Object.fromEntries(
      Object.entries(values).filter(([key, value]) => visibleFieldNames.has(key) && String(value ?? '').trim() !== String(baseline[key] ?? '').trim()),
    ) as Record<string, string>
    const changedCompositionPieces = buildChangedHektorCompositionPieces(compositionPieces, buildHektorCompositionPiecesFromDetail(detail))
    if (Object.keys(changedValues).length === 0 && changedCompositionPieces.length === 0) {
      setError('Aucune modification a envoyer.')
      return
    }
    setPending(true)
    try {
      const job = await createUpdateHektorAnnonceFieldsJob({
        dossier,
        fields: {
          propertyProfile: profileKind,
          wizardFields: changedValues,
          compositionPieces: changedCompositionPieces,
        },
        priority: 14,
      })
      props.onJobCreated?.(job)
      setMessage(null)
      props.onCancel?.()
    } catch (submitError) {
      setError(submitError instanceof Error ? submitError.message : 'Modification Hektor impossible.')
    } finally {
      setPending(false)
    }
  }

  const renderUpdateSection = (section: DraftAnnonceWizardGroup) => (
    <section key={section.title} className={`hektor-advanced-section hektor-advanced-section-step-${section.step}`}>
      <div className="hektor-advanced-section-head">
        <strong>{section.title}</strong>
        <span>{section.fields.length}</span>
      </div>
      <div className="hektor-advanced-grid">
        {section.fields.map((field) => (
          field.multiline ? (
            <label key={field.name} className="hektor-inline-textarea hektor-advanced-textarea">
              <span>{field.label}</span>
              <textarea value={values[field.name] ?? ''} onChange={(event) => updateField(field.name, event.target.value)} placeholder={field.placeholder ?? draftAnnonceWizardPlaceholder(field)} />
            </label>
          ) : field.options ? (
            <label key={field.name}>
              <span>{field.label}</span>
              <select value={values[field.name] ?? ''} onChange={(event) => updateField(field.name, event.target.value)}>
                {field.options.some((option) => option.value === '') ? null : <option value="">-</option>}
                {field.options.map((option) => (
                  <option key={`${field.name}-${option.value}`} value={option.value}>{option.label}</option>
                ))}
              </select>
            </label>
          ) : (
            <label key={field.name}>
              <span>{field.label}</span>
              <input value={values[field.name] ?? ''} onChange={(event) => updateField(field.name, event.target.value)} inputMode={field.inputMode} placeholder={field.placeholder ?? draftAnnonceWizardPlaceholder(field)} />
            </label>
          )
        ))}
      </div>
    </section>
  )

  return (
    <form className={`hektor-inline-form hektor-annonce-update-form ${props.compact ? 'is-compact' : ''} ${props.fieldPanel ? 'is-field-panel' : ''}`} onSubmit={handleSubmit}>
      <div className="hektor-inline-form-head">
        <span className="hektor-inline-icon" aria-hidden="true">M</span>
        <div>
          <strong>Modifier dans Hektor</strong>
          <small>Memes pages et champs techniques que la creation Hektor.</small>
        </div>
      </div>
      <div className="hektor-advanced-sections">
        {sectionsBeforeComposition.map(renderUpdateSection)}
        <HektorCompositionPiecesEditor
          title="4. Composition"
          subtitle="Ajoute ou corrige les pieces une par une, comme dans Hektor."
          pieces={compositionPieces}
          draft={compositionDraft}
          disabled={pending}
          className="hektor-advanced-section hektor-advanced-section-step-4"
          onDraftChange={updateCompositionDraft}
          onAddDraft={addCompositionDraft}
          onPieceChange={updateCompositionPiece}
          onRemovePiece={removeCompositionPiece}
          onRestorePiece={restoreCompositionPiece}
        />
        {sectionsAfterComposition.map(renderUpdateSection)}
      </div>
      <div className="hektor-inline-actions">
        <button type="submit" disabled={pending}>{pending ? 'Envoi...' : 'Envoyer vers Hektor'}</button>
        {props.onCancel ? <button className="button-subtle" type="button" onClick={props.onCancel} disabled={pending}>Fermer</button> : null}
        {message ? <span className="hektor-inline-feedback is-success">{message}</span> : null}
        {error ? <span className="hektor-inline-feedback is-error">{error}</span> : null}
      </div>
    </form>
  )
}

function HektorAnnonceFieldDetailPanel(props: {
  dossier: Pick<Dossier, 'titre_bien' | 'prix' | 'numero_dossier' | 'diffusable' | 'type_bien'>
  detail: DossierDetailPayload
}) {
  const groups = buildHektorWizardDetailGroups(props.dossier, props.detail)
  const compositionPieces = buildHektorCompositionPiecesFromDetail(props.detail)
  const groupsBeforeComposition = groups.filter((group) => group.step < 4)
  const groupsAfterComposition = groups.filter((group) => group.step > 4)
  const totalFields = groups.reduce((count, group) => count + group.fields.length, 0) + compositionPieces.length
  const filledFields = groups.reduce((count, group) => count + group.fields.filter((field) => String(field.value ?? '').trim()).length, 0)
    + compositionPieces.filter((piece) => hektorCompositionPieceHasContent(piece)).length
  const renderDetailGroup = (group: HektorWizardDetailGroup, index: number) => {
    const groupFilled = group.fields.filter((field) => String(field.value ?? '').trim()).length
    return (
      <details key={`hektor-detail-group-${group.title}`} className="hektor-detail-field-group" open={index < 3}>
        <summary>
          <strong>{group.title}</strong>
          <span>{groupFilled}/{group.fields.length}</span>
        </summary>
        <div className="hektor-detail-field-grid">
          {group.fields.map((field) => (
            <article key={`hektor-detail-field-${group.title}-${field.name}`} className={String(field.value ?? '').trim() ? 'is-filled' : 'is-empty'}>
              <span>{field.label}</span>
              <strong>{wizardDisplayValue(field, field.value)}</strong>
              <small>{field.name}</small>
            </article>
          ))}
        </div>
      </details>
    )
  }

  return (
    <section className="detail-section detail-hektor-fields-section">
      <div className="section-header">
        <DetailSectionTitle icon="summary" title="Champs Hektor" />
        <span>{filledFields}/{totalFields} renseignes</span>
      </div>
      <div className="hektor-detail-field-groups">
        {groupsBeforeComposition.map(renderDetailGroup)}
        <details className="hektor-detail-field-group hektor-detail-composition-group" open>
          <summary>
            <strong>4. Composition</strong>
            <span>{compositionPieces.length}</span>
          </summary>
          {compositionPieces.length ? (
            <div className="hektor-detail-composition-list">
              {compositionPieces.map((piece, index) => (
                <article key={`detail-composition-${piece.localId}`}>
                  <span>{index + 1}</span>
                  <strong>{hektorCompositionPieceDisplayTitle(piece)}</strong>
                  <small>{[
                    piece.surfacePiece ? `${piece.surfacePiece} m2` : '',
                    piece.etagePiece ? `Etage ${piece.etagePiece}` : '',
                    hektorCompositionPieceTypeLabel(piece.idTypePiece, piece.typeLabel),
                  ].filter(Boolean).join(' - ') || 'Piece Hektor'}</small>
                </article>
              ))}
            </div>
          ) : (
            <p className="hektor-detail-composition-empty">Aucune piece detaillee remontee par la synchronisation Hektor.</p>
          )}
        </details>
        {groupsAfterComposition.map((group, index) => renderDetailGroup(group, index + groupsBeforeComposition.length + 1))}
      </div>
    </section>
  )
}

function HektorMandantContactForm(props: {
  dossier: Pick<Dossier, 'app_dossier_id' | 'hektor_annonce_id' | 'negociateur_email'>
  compact?: boolean
  initialOpen?: boolean
  onJobCreated?: (job: ConsoleJob) => void
  onMissingNegotiator?: MissingNegotiatorHandler
}) {
  const [open, setOpen] = useState(Boolean(props.initialOpen))
  const [civility, setCivility] = useState('')
  const [lastName, setLastName] = useState('')
  const [firstName, setFirstName] = useState('')
  const [email, setEmail] = useState('')
  const [phone, setPhone] = useState('')
  const [address, setAddress] = useState('')
  const [postalCode, setPostalCode] = useState('')
  const [city, setCity] = useState('')
  const [pending, setPending] = useState(false)
  const [message, setMessage] = useState<string | null>(null)
  const [error, setError] = useState<string | null>(null)

  useEffect(() => {
    setOpen(Boolean(props.initialOpen))
    setCivility('')
    setLastName('')
    setFirstName('')
    setEmail('')
    setPhone('')
    setAddress('')
    setPostalCode('')
    setCity('')
    setMessage(null)
    setError(null)
    setPending(false)
  }, [props.dossier.app_dossier_id, props.initialOpen])

  const handleSubmit = async (event: FormEvent<HTMLFormElement>) => {
    event.preventDefault()
    setMessage(null)
    setError(null)
    if (!lastName.trim() || !email.trim()) {
      setError('Nom et email sont obligatoires pour créer le contact Hektor.')
      return
    }
    if (!hasHektorNegotiator(props.dossier)) {
      props.onMissingNegotiator?.(props.dossier)
      return
    }
    setPending(true)
    try {
      const job = await createHektorMandantContactJob({
        dossier: props.dossier,
        contact: {
          civility,
          lastName,
          firstName,
          email,
          phone,
          address,
          postalCode,
          city,
        },
        priority: 18,
      })
      setCivility('')
      setLastName('')
      setFirstName('')
      setEmail('')
      setPhone('')
      setAddress('')
      setPostalCode('')
      setCity('')
      props.onJobCreated?.(job)
      setMessage(null)
      setOpen(false)
    } catch (submitError) {
      setError(submitError instanceof Error ? submitError.message : 'Creation du mandant impossible.')
    } finally {
      setPending(false)
    }
  }

  return (
    <div className={`hektor-mandant-create-shell ${props.compact ? 'is-compact' : ''} ${open ? 'is-open' : ''}`}>
      {!open ? (
        <button className="hektor-mandant-add-card" type="button" onClick={() => setOpen(true)}>
          <span aria-hidden="true">+</span>
          <strong>Ajouter un mandant</strong>
          <small>Nouveau contact Hektor associe a cette annonce</small>
        </button>
      ) : null}
      {open ? (
    <form className={`hektor-inline-form hektor-mandant-create-form ${props.compact ? 'is-compact' : ''}`} onSubmit={handleSubmit}>
      <div className="hektor-inline-form-head">
        <span className="hektor-inline-icon" aria-hidden="true">+</span>
        <div>
          <strong>Créer un mandant Hektor</strong>
          <small>Le contact est créé puis associé automatiquement à cette annonce.</small>
        </div>
      </div>
      <div className="hektor-inline-grid">
        <label className="is-small">
          <span>Civilite</span>
          <select value={civility} onChange={(event) => setCivility(event.target.value)}>
            <option value="">-</option>
            <option value="M.">M.</option>
            <option value="Mme.">Mme.</option>
            <option value="Mlle.">Mlle.</option>
          </select>
        </label>
        <label>
          <span>Nom</span>
          <input value={lastName} onChange={(event) => setLastName(event.target.value)} placeholder="Nom" required />
        </label>
        <label>
          <span>Prenom</span>
          <input value={firstName} onChange={(event) => setFirstName(event.target.value)} placeholder="Prenom" />
        </label>
        <label>
          <span>Email</span>
          <input value={email} onChange={(event) => setEmail(event.target.value)} type="email" placeholder="email@exemple.fr" required />
        </label>
        <label>
          <span>Telephone</span>
          <input value={phone} onChange={(event) => setPhone(event.target.value)} inputMode="tel" placeholder="Portable" />
        </label>
        <label>
          <span>Adresse</span>
          <input value={address} onChange={(event) => setAddress(event.target.value)} placeholder="Adresse" />
        </label>
        <label className="is-small">
          <span>CP</span>
          <input value={postalCode} onChange={(event) => setPostalCode(event.target.value)} inputMode="numeric" />
        </label>
        <label>
          <span>Ville</span>
          <input value={city} onChange={(event) => setCity(event.target.value)} />
        </label>
      </div>
      <div className="hektor-inline-actions">
        <button type="submit" disabled={pending}>{pending ? 'Envoi...' : 'Créer et associer'}</button>
        <button className="button-subtle" type="button" onClick={() => setOpen(false)} disabled={pending}>Annuler</button>
        {message ? <span className="hektor-inline-feedback is-success">{message}</span> : null}
        {error ? <span className="hektor-inline-feedback is-error">{error}</span> : null}
      </div>
    </form>
      ) : null}
    </div>
  )
}

