function pageLabel(total: number, pageSize: number, page: number) {
  const from = total === 0 ? 0 : (page - 1) * pageSize + 1
  const to = Math.min(page * pageSize, total)
  return `${from}-${to} / ${new Intl.NumberFormat('fr-FR').format(total)}`
}

