  useEffect(() => {
    if (hasSupabaseEnv && !session) return
    let cancelled = false
    let refreshQueued = false
    async function refreshHektorActionJobs() {
      try {
        const trackedIds = hektorActionRelatedJobIds(hektorActionJobsRef.current)
        const [activeJobs, trackedJobs] = await Promise.all([
          loadActiveHektorActionJobs(),
          loadConsoleJobsByIds(trackedIds),
        ])
        if (cancelled) return
        updateHektorActionJobs((current) => {
          const previousById = new Map(current.map((job) => [job.id, job]))
          const nextById = new Map(current.map((job) => [job.id, job]))
          for (const job of [...activeJobs, ...trackedJobs]) nextById.set(job.id, job)
          const transitioned = [...nextById.values()].some((job) => {
            const previous = previousById.get(job.id)
            return previous && isConsoleJobActive(previous) && !isConsoleJobActive(job)
          })
          if (transitioned && !refreshQueued) {
            refreshQueued = true
            window.setTimeout(() => {
              refreshQueued = false
              setDataReloadKey((value) => value + 1)
            }, 600)
          }
          return [...nextById.values()]
            .sort((left, right) => new Date(right.requested_at).getTime() - new Date(left.requested_at).getTime())
            .slice(0, 12)
        })
      } catch (error) {
        if (!cancelled) console.warn('Hektor action jobs refresh failed', error)
      }
    }
    void refreshHektorActionJobs()
    const interval = window.setInterval(refreshHektorActionJobs, 5000)
    return () => {
      cancelled = true
      window.clearInterval(interval)
    }
  }, [session])

  useEffect(() => {
    if (hasSupabaseEnv && !session) return
    const jobsToResolve = visibleHektorActionPopupJobs
      .filter((job) => job.status === 'done')
      .map((job) => ({ job, id: hektorCreatedAnnonceId(job) }))
      .filter((entry): entry is { job: ConsoleJob; id: string } => Boolean(entry.id))
      .filter(({ id }) => !hektorActionLinkedDossiers[id])
    if (jobsToResolve.length === 0) return
    let cancelled = false
    async function resolveCreatedDossiers() {
      const resolvedEntries: Array<[string, Dossier]> = []
      const uniqueEntries = new Map<string, { job: ConsoleJob; id: string }>()
      for (const entry of jobsToResolve) uniqueEntries.set(`${entry.job.job_type}:${entry.id}`, entry)
      for (const { job, id } of uniqueEntries.values()) {
        try {
          const dossier = await loadHektorActionAppDossier(job, dataScope)
          if (dossier) resolvedEntries.push([id, dossier])
        } catch (error) {
          console.warn('Hektor created dossier lookup failed', error)
        }
      }
      if (cancelled || resolvedEntries.length === 0) return
      setHektorActionLinkedDossiers((current) => {
        const next = { ...current }
        for (const [id, dossier] of resolvedEntries) next[id] = dossier
        return next
      })
    }
    void resolveCreatedDossiers()
    return () => {
      cancelled = true
    }
  }, [dataScope, hektorActionLinkedDossiers, session, visibleHektorActionPopupJobs])

  useEffect(() => {
    if (hasSupabaseEnv && !session) return
    const queuedEntries = Object.entries(draftAnnonceQueuedPhotos).filter(([, photos]) => photos.length > 0)
    if (queuedEntries.length === 0) return
    let cancelled = false

    async function enqueueDraftAnnoncePhotos() {
      for (const [createJobId, photos] of queuedEntries) {
        if (cancelled || draftAnnoncePhotoUploadStartedRef.current.has(createJobId)) continue
        const createJob = hektorActionJobs.find((job) => job.id === createJobId)
        if (!createJob) continue
        if (createJob.status === 'error') {
          draftAnnoncePhotoUploadStartedRef.current.delete(createJobId)
          setDraftAnnonceQueuedPhotos((current) => {
            const next = { ...current }
            delete next[createJobId]
            return next
          })
          setErrorMessage("Les photos n'ont pas ete envoyees car la creation de l annonce Hektor a echoue.")
          continue
        }
        if (createJob.status !== 'done') continue

        const hektorAnnonceId = hektorCreatedAnnonceId(createJob)
        if (!hektorAnnonceId) continue
        draftAnnoncePhotoUploadStartedRef.current.add(createJobId)

        try {
          let dossier: Dossier | null = hektorActionLinkedDossiers[hektorAnnonceId] ?? null
          if (!dossier) {
            dossier = await loadHektorActionAppDossier(createJob, dataScope)
            if (dossier && !cancelled) {
              setHektorActionLinkedDossiers((current) => current[hektorAnnonceId] ? current : { ...current, [hektorAnnonceId]: dossier as Dossier })
            }
          }
          if (cancelled) return
          if (!dossier) {
            draftAnnoncePhotoUploadStartedRef.current.delete(createJobId)
            continue
          }

          let queuedCount = 0
          let failedCount = 0
          for (const photo of photos) {
            try {
              const photoJob = await createUploadHektorPhotoJob({
                dossier,
                file: photo.file,
                visible: photo.visible,
                priority: 18,
              })
              if (cancelled) return
              rememberHektorActionJob(photoJob)
              queuedCount += 1
            } catch (error) {
              failedCount += 1
              console.warn('Draft annonce photo upload job failed', error)
            }
          }
          if (cancelled) return
          setDraftAnnonceQueuedPhotos((current) => {
            const next = { ...current }
            delete next[createJobId]
            return next
          })
          draftAnnoncePhotoUploadStartedRef.current.delete(createJobId)
          if (queuedCount > 0) setNoticeMessage(`${queuedCount} photo(s) ajoutee(s) a la file du worker photos Hektor.`)
          if (failedCount > 0) setErrorMessage(`${failedCount} photo(s) n ont pas pu etre preparee(s) pour le worker photos.`)
        } catch (error) {
          if (cancelled) return
          draftAnnoncePhotoUploadStartedRef.current.delete(createJobId)
          setErrorMessage(error instanceof Error ? error.message : 'Impossible de preparer les photos Hektor')
        }
      }
    }

    void enqueueDraftAnnoncePhotos()
    return () => {
      cancelled = true
    }
  }, [dataScope, draftAnnonceQueuedPhotos, hektorActionJobs, hektorActionLinkedDossiers, session])

