  function dismissHektorActionPopup(jobId: string) {
    const job = hektorActionJobsRef.current.find((item) => item.id === jobId)
    const relatedIds = job ? [job.id, hektorJobSyncJobId(job)].filter((id): id is string => Boolean(id)) : [jobId]
    setDismissedHektorActionJobIds((current) => Array.from(new Set([...current, ...relatedIds])))
  }

  async function openHektorActionAppDossier(job: ConsoleJob) {
    const hektorAnnonceId = hektorCreatedAnnonceId(job)
    if (!hektorAnnonceId) return
    let dossier: Dossier | null = hektorActionLinkedDossiers[hektorAnnonceId] ?? null
    if (!dossier) {
      dossier = await loadHektorActionAppDossier(job, dataScope)
      if (dossier) {
        setHektorActionLinkedDossiers((current) => ({ ...current, [hektorAnnonceId]: dossier as Dossier }))
      }
    }
    if (!dossier) {
      setNoticeMessage("Annonce creee dans Hektor. L'app attend encore la remontee de la fiche complete; le bouton s'activera automatiquement.")
      setDataReloadKey((value) => value + 1)
      return
    }
    setScreen('mandats')
    if ('detail_payload_json' in dossier) setSelectedDossier(dossier as DetailedDossier)
    setSelectedDossierId(dossier.app_dossier_id)
    setSelectedMandatId(dossier.app_dossier_id)
    setDataReloadKey((value) => value + 1)
    setDetailOpen(true)
    dismissHektorActionPopup(job.id)
  }

  async function handleCreateDraftAnnonce(event: FormEvent<HTMLFormElement>) {
    event.preventDefault()
    if (draftAnnonceStep !== 'diffusion') {
      moveDraftAnnonceStep(1)
      return
    }
    if (!draftAnnonceAgency.trim()) {
      setErrorMessage('Choisis une agence avant de creer l annonce Hektor.')
      setDraftAnnonceStep('offre')
      return
    }
    if (!selectedDraftNegotiator) {
      setErrorMessage(profile?.role === 'commercial' ? 'Impossible d identifier ton acces negociateur Hektor.' : 'Choisis le negociateur Hektor qui portera l annonce.')
      setDraftAnnonceStep('offre')
      return
    }
    const hasNewInitialMandant = draftMandantChoice === 'new' && [draftMandantCivility, draftMandantLastName, draftMandantFirstName, draftMandantEmail, draftMandantPhone, draftMandantAddress, draftMandantPostalCode, draftMandantCity].some((value) => value.trim())
    const hasExistingInitialMandant = draftMandantChoice === 'existing' && /^\d+$/.test(draftExistingMandantId.trim())
    if (draftMandantChoice === 'existing' && !hasExistingInitialMandant) {
      setErrorMessage('Choisis un contact dans la liste pour associer le mandant.')
      setDraftAnnonceStep('mandatPrix')
      return
    }
    if (draftMandantChoice === 'new' && !hasNewInitialMandant) {
      setErrorMessage('Renseigne le nouveau mandant ou repasse sur "Aucun mandant".')
      setDraftAnnonceStep('mandatPrix')
      return
    }
    if (hasNewInitialMandant && (!draftMandantLastName.trim() || !draftMandantEmail.trim())) {
      setErrorMessage('Pour ajouter un mandant initial, renseigne au minimum le nom et l email.')
      setDraftAnnonceStep('mandatPrix')
      return
    }
    const queuedPhotos = draftAnnoncePhotoDrafts.map(({ id, file, visible }) => ({ id, file, visible }))
    const hektorWizardFields = filterDraftAnnonceWizardFieldsForProfile(draftAnnonceWizardFields, draftAnnonceTypeRules.kind)
    const setHektorWizardField = (key: string, value: string) => {
      const clean = value.trim()
      if (clean) hektorWizardFields[key] = clean
    }
    const draftAdvancedValue = (key: DraftAnnonceAdvancedKey) => (
      isDraftAnnonceAdvancedFieldVisibleForProfile(draftAnnonceTypeRules.kind, key) ? draftAnnonceAdvanced[key] : null
    )
    if (draftAnnonceTypeRules.surfaceMode === 'terrain') setHektorWizardField('surfterrain', draftAnnonceAdvanced.landSurface)
    if (draftAnnonceTypeRules.surfaceMode === 'garage') setHektorWizardField('SURFACE_GARAGE', draftAnnonceAdvanced.garageSurface)
    if (draftAnnonceTypeRules.showLevels) setHektorWizardField('NB_NIVEAUX', draftAnnonceLevelCount)
    if (draftAnnonceTypeRules.showGarageCount) setHektorWizardField('GARAGE_BOX', draftAnnonceAdvanced.garageCount)
    if (draftAnnonceTypeRules.showGardenPool) {
      setHektorWizardField('surfterrain', draftAnnonceAdvanced.landSurface)
      setHektorWizardField('JARDIN-', draftAnnonceAdvanced.garden)
      setHektorWizardField('PISCINE-', draftAnnonceAdvanced.pool)
    }
    if (draftAnnonceTypeRules.showExposure) setHektorWizardField('EXPOSITION', draftAnnonceAdvanced.exposure)
    if (draftAnnonceTypeRules.showView) setHektorWizardField('vuee', draftAnnonceAdvanced.view)
    setDraftAnnoncePending(true)
    setNoticeMessage(null)
    setErrorMessage(null)
    try {
      const job = await createHektorDraftAnnonceJob({
        title: draftAnnonceTitle,
        description: draftAnnonceAdvanced.description,
        agenceNom: draftAnnonceAgency,
        hektorUserId: selectedDraftNegotiator.idUser,
        hektorNegociateurId: selectedDraftNegotiator.hektorNegociateurId,
        hektorUserLabel: selectedDraftNegotiator.label,
        hektorUserEmail: selectedDraftNegotiator.email,
        creationStatus: draftAnnonceCreationStatus,
        propertyType: draftAnnoncePropertyTypeLabel(draftAnnonceTypeId),
        propertyProfile: draftAnnonceTypeRules.kind,
        hektorIdType: draftAnnonceTypeId,
        offerType: 'sale',
        address: draftAnnonceAddress,
        postalCode: draftAnnoncePostalCode,
        city: draftAnnonceCity,
        price: draftAnnoncePrice,
        netSellerPrice: draftAdvancedValue('netSellerPrice'),
        surface: draftAnnonceTypeRules.surfaceMode === 'habitable' ? draftAnnonceSurface : null,
        carrezSurface: draftAdvancedValue('carrezSurface'),
        livingSurface: draftAdvancedValue('livingSurface'),
        roomCount: draftAnnonceTypeRules.showRooms ? draftAnnonceRoomCount : null,
        bedroomCount: draftAnnonceTypeRules.showBedrooms ? draftAnnonceBedroomCount : null,
        levelCount: draftAnnonceTypeRules.showLevels ? draftAnnonceLevelCount : null,
        bathroomCount: draftAdvancedValue('bathroomCount'),
        showerRoomCount: draftAdvancedValue('showerRoomCount'),
        wcCount: draftAdvancedValue('wcCount'),
        kitchen: draftAdvancedValue('kitchen'),
        exposure: draftAdvancedValue('exposure'),
        view: draftAdvancedValue('view'),
        interiorState: draftAdvancedValue('interiorState'),
        exteriorState: draftAdvancedValue('exteriorState'),
        landSurface: draftAnnonceTypeRules.surfaceMode === 'terrain' || draftAnnonceTypeRules.showGardenPool ? draftAnnonceAdvanced.landSurface : null,
        garden: draftAdvancedValue('garden'),
        terraceCount: draftAdvancedValue('terraceCount'),
        garageCount: draftAdvancedValue('garageCount'),
        garageSurface: draftAdvancedValue('garageSurface'),
        parkingInsideCount: draftAdvancedValue('parkingInsideCount'),
        parkingOutsideCount: draftAdvancedValue('parkingOutsideCount'),
        pool: draftAdvancedValue('pool'),
        constructionYear: draftAdvancedValue('constructionYear'),
        dpeValue: draftAdvancedValue('dpeValue'),
        gesValue: draftAdvancedValue('gesValue'),
        coproLots: draftAdvancedValue('coproLots'),
        coproCharges: draftAdvancedValue('coproCharges'),
        coproQuotePart: draftAdvancedValue('coproQuotePart'),
        coproWorksFund: draftAdvancedValue('coproWorksFund'),
        wizardFields: hektorWizardFields,
        compositionPieces: draftAnnonceCompositionPieces
          .filter((piece) => hektorCompositionPieceHasContent(piece))
          .map((piece) => hektorCompositionPieceToInput(piece, 'add')),
        note: draftAnnonceNote,
        initialMandantContactId: hasExistingInitialMandant ? draftExistingMandantId.trim() : null,
        initialMandantContactLabel: hasExistingInitialMandant ? mandantContactOptionTitle(selectedDraftExistingMandant) : null,
        initialMandant: hasNewInitialMandant ? {
          civility: draftMandantCivility,
          lastName: draftMandantLastName,
          firstName: draftMandantFirstName,
          email: draftMandantEmail,
          phone: draftMandantPhone,
          address: draftMandantAddress,
          postalCode: draftMandantPostalCode,
          city: draftMandantCity,
        } : null,
        priority: 10,
      })
      rememberHektorActionJob(job)
      if (queuedPhotos.length) {
        setDraftAnnonceQueuedPhotos((current) => ({ ...current, [job.id]: queuedPhotos }))
        clearDraftAnnoncePhotoDrafts()
      }
      setDraftAnnonceModalOpen(false)
      setNoticeMessage(queuedPhotos.length
        ? `${queuedPhotos.length} photo(s) preparee(s). Elles seront envoyees par le worker photos des que l annonce sera synchronisee dans l app.`
        : null)
    } catch (error) {
      setErrorMessage(error instanceof Error ? error.message : 'Impossible de creer la demande d annonce Hektor')
    } finally {
      setDraftAnnoncePending(false)
    }
  }

