function splitEmailList(value: string) {
  return value
    .split(/[;,\s]+/g)
    .map((item) => item.trim().toLowerCase())
    .filter((item, index, list) => item && item.includes('@') && list.indexOf(item) === index)
}

function joinEmailList(values: string[]) {
  return values
    .map((item) => item.trim().toLowerCase())
    .filter((item, index, list) => item && item.includes('@') && list.indexOf(item) === index)
    .join(', ')
}

function detailContactAgendaEmail(contact: DetailContact) {
  return safeText(contact.email).toLowerCase()
}

function detailContactAgendaLabel(contact: DetailContact) {
  return contactPersonDisplayName(contact) || contact.name || contact.email || contact.phone || 'Contact'
}

function contactOptionAgendaEmail(contact: MandantContactSearchOption) {
  return safeText(contact.email).toLowerCase()
}

function hektorContactInputAgendaEmail(contact: HektorContactIdentityInput) {
  return safeText(contact.email).toLowerCase()
}

type GoogleAgendaInviteeContactLink = {
  email: string
  label?: string | null
  hektorContactId?: string | null
  source?: string | null
}

type GoogleAgendaLinkedInviteeOption = {
  key: string
  label: string
  email: string
  meta: string
  hektorContactId?: string | null
  link: GoogleAgendaInviteeContactLink | null
}

function normalizeGoogleAgendaInviteeContactLink(value: unknown): GoogleAgendaInviteeContactLink | null {
  if (!value || typeof value !== 'object') return null
  const record = value as Record<string, unknown>
  const email = safeText(record.email).toLowerCase()
  if (!email || !email.includes('@')) return null
  return {
    email,
    label: safeText(record.label) || null,
    hektorContactId: safeText(record.hektor_contact_id) || safeText(record.hektorContactId) || null,
    source: safeText(record.source) || null,
  }
}

function mergeGoogleAgendaInviteeContactLinks(
  current: GoogleAgendaInviteeContactLink[],
  next: GoogleAgendaInviteeContactLink[],
  emailScope?: string[],
) {
  const allowed = emailScope ? new Set(emailScope.map((email) => email.trim().toLowerCase()).filter(Boolean)) : null
  const links = new Map<string, GoogleAgendaInviteeContactLink>()
  const addLink = (link: GoogleAgendaInviteeContactLink) => {
    const normalized = normalizeGoogleAgendaInviteeContactLink(link)
    if (!normalized || (allowed && !allowed.has(normalized.email))) return
    const existing = links.get(normalized.email)
    links.set(normalized.email, {
      email: normalized.email,
      label: normalized.label || existing?.label || null,
      hektorContactId: normalized.hektorContactId || existing?.hektorContactId || null,
      source: normalized.source || existing?.source || null,
    })
  }
  current.forEach(addLink)
  next.forEach(addLink)
  return Array.from(links.values())
}

function googleAgendaEventInviteeContacts(event: GoogleCalendarEventLink) {
  const raw = event.metadata_json?.attendee_contacts
  if (!Array.isArray(raw)) return []
  return raw
    .map(normalizeGoogleAgendaInviteeContactLink)
    .filter((item): item is GoogleAgendaInviteeContactLink => Boolean(item))
}

function googleAgendaInviteeContactMetadata(links: GoogleAgendaInviteeContactLink[], attendees: string[]) {
  return mergeGoogleAgendaInviteeContactLinks(links, [], attendees).map((link) => ({
    email: link.email,
    label: link.label ?? null,
    hektor_contact_id: link.hektorContactId ?? null,
    source: link.source ?? null,
  }))
}

function detailContactAgendaLink(contact: DetailContact, email = detailContactAgendaEmail(contact)): GoogleAgendaInviteeContactLink | null {
  if (!email) return null
  return {
    email,
    label: detailContactAgendaLabel(contact),
    hektorContactId: detailContactDirectoryId(contact),
    source: 'annonce_contact',
  }
}

function contactOptionAgendaLink(contact: MandantContactSearchOption, email = contactOptionAgendaEmail(contact)): GoogleAgendaInviteeContactLink | null {
  if (!email) return null
  return {
    email,
    label: mandantContactOptionTitle(contact),
    hektorContactId: contact.hektor_contact_id,
    source: 'contact_search',
  }
}

function googleAgendaRelationRoleLabel(value: string | null | undefined) {
  const text = safeText(value).replace(/[_-]+/g, ' ').toLowerCase()
  if (!text) return 'Relation annonce'
  if (text.includes('proprietaire') || text.includes('mandant')) return 'Mandant'
  if (text.includes('acquereur')) return 'Acquereur'
  if (text.includes('offre')) return 'Offre'
  return text.charAt(0).toUpperCase() + text.slice(1)
}

function contactInputAgendaLabel(contact: HektorContactIdentityInput) {
  return [contact.civility, contact.firstName, contact.lastName]
    .map((value) => safeText(value))
    .filter(Boolean)
    .join(' ') || safeText(contact.companyName) || safeText(contact.email)
}

type GoogleAgendaWindow = {
  start: string
  end: string
}

type GoogleAgendaViewMode = 'day' | 'week'

function dateInputFromDateTimeLocal(value: string | null | undefined) {
  const date = new Date(value ?? '')
  if (Number.isNaN(date.getTime())) return toDateTimeLocalValue(new Date()).slice(0, 10)
  return toDateTimeLocalValue(date).slice(0, 10)
}

function dateInputToLocalDate(dayValue: string) {
  const date = new Date(`${dayValue || toDateTimeLocalValue(new Date()).slice(0, 10)}T12:00:00`)
  return Number.isNaN(date.getTime()) ? new Date() : date
}

function addDaysToDateInput(dayValue: string, days: number) {
  const date = dateInputToLocalDate(dayValue)
  date.setDate(date.getDate() + days)
  return toDateTimeLocalValue(date).slice(0, 10)
}

function googleAgendaDayRange(dayValue: string) {
  const cleanDay = dayValue || toDateTimeLocalValue(new Date()).slice(0, 10)
  return {
    startAt: `${cleanDay}T08:00`,
    endAt: `${cleanDay}T19:00`,
  }
}

function googleAgendaWeekDays(dayValue: string) {
  const date = dateInputToLocalDate(dayValue)
  const mondayOffset = (date.getDay() + 6) % 7
  date.setDate(date.getDate() - mondayOffset)
  const start = toDateTimeLocalValue(date).slice(0, 10)
  return Array.from({ length: 7 }, (_, index) => addDaysToDateInput(start, index))
}

function googleAgendaPeriodDays(dayValue: string, mode: GoogleAgendaViewMode) {
  return mode === 'week' ? googleAgendaWeekDays(dayValue) : [dayValue || toDateTimeLocalValue(new Date()).slice(0, 10)]
}

function googleAgendaPeriodRange(dayValue: string, mode: GoogleAgendaViewMode) {
  const days = googleAgendaPeriodDays(dayValue, mode)
  const first = days[0] ?? dayValue
  const last = days[days.length - 1] ?? first
  return {
    startAt: `${first}T08:00`,
    endAt: `${last}T19:00`,
  }
}

function googleAgendaDayLabel(dayValue: string) {
  return new Intl.DateTimeFormat('fr-FR', { weekday: 'short', day: '2-digit', month: '2-digit' }).format(dateInputToLocalDate(dayValue))
}

function googleAgendaRangeLabel(dayValue: string, mode: GoogleAgendaViewMode) {
  const days = googleAgendaPeriodDays(dayValue, mode)
  if (mode === 'day') return googleAgendaDayLabel(days[0] ?? dayValue)
  return `${googleAgendaDayLabel(days[0] ?? dayValue)} - ${googleAgendaDayLabel(days[days.length - 1] ?? dayValue)}`
}

function googleAgendaEventOverlapsDay(event: GoogleCalendarEventLink, dayValue: string) {
  const range = googleAgendaDayRange(dayValue)
  const start = new Date(event.starts_at).getTime()
  const end = new Date(event.ends_at).getTime()
  const dayStart = new Date(range.startAt).getTime()
  const dayEnd = new Date(range.endAt).getTime()
  return Number.isFinite(start) && Number.isFinite(end) && end > dayStart && start < dayEnd
}

function googleAgendaEventsForDay(events: GoogleCalendarEventLink[], dayValue: string) {
  return events
    .filter((event) => event.status !== 'deleted' && googleAgendaEventOverlapsDay(event, dayValue))
    .sort((left, right) => new Date(left.starts_at).getTime() - new Date(right.starts_at).getTime())
}

function mergeGoogleCalendarEventLinks(events: GoogleCalendarEventLink[]) {
  const byId = new Map<string, GoogleCalendarEventLink>()
  for (const event of events) {
    byId.set(event.id, event)
  }
  return Array.from(byId.values())
}

function minutesBetweenWindow(window: GoogleAgendaWindow) {
  const start = new Date(window.start)
  const end = new Date(window.end)
  return Math.max(0, Math.round((end.getTime() - start.getTime()) / 60000))
}

function addMinutesIso(value: string, minutes: number) {
  const date = new Date(value)
  date.setMinutes(date.getMinutes() + minutes)
  return date.toISOString()
}

function buildGoogleAgendaSuggestedWindows(freeWindows: GoogleAgendaWindow[], requestedMinutes: number, maxCount = 5) {
  const cleanMinutes = Number.isFinite(requestedMinutes) && requestedMinutes > 0 ? requestedMinutes : 60
  const stepMinutes = 15
  const suggestions: GoogleAgendaWindow[] = []
  for (const window of freeWindows) {
    let cursor = new Date(window.start).getTime()
    const end = new Date(window.end).getTime()
    while (cursor + cleanMinutes * 60000 <= end && suggestions.length < maxCount) {
      const startIso = new Date(cursor).toISOString()
      suggestions.push({ start: startIso, end: addMinutesIso(startIso, cleanMinutes) })
      cursor += stepMinutes * 60000
    }
    if (suggestions.length >= maxCount) break
  }
  return suggestions
}

function buildGoogleAgendaDayWindows(dayValue: string, availability: GoogleCalendarAvailability | null) {
  const range = googleAgendaDayRange(dayValue)
  const dayStart = new Date(range.startAt)
  const dayEnd = new Date(range.endAt)
  const busy = (availability?.busy ?? [])
    .map((slot) => {
      const start = new Date(slot.start ?? '')
      const end = new Date(slot.end ?? '')
      if (Number.isNaN(start.getTime()) || Number.isNaN(end.getTime())) return null
      const clampedStart = new Date(Math.max(start.getTime(), dayStart.getTime()))
      const clampedEnd = new Date(Math.min(end.getTime(), dayEnd.getTime()))
      if (clampedEnd <= clampedStart) return null
      return { start: clampedStart.toISOString(), end: clampedEnd.toISOString() }
    })
    .filter((slot): slot is GoogleAgendaWindow => Boolean(slot))
    .sort((left, right) => new Date(left.start).getTime() - new Date(right.start).getTime())

  const free: GoogleAgendaWindow[] = []
  let cursor = dayStart.getTime()
  for (const slot of busy) {
    const start = new Date(slot.start).getTime()
    const end = new Date(slot.end).getTime()
    if (start > cursor) {
      free.push({ start: new Date(cursor).toISOString(), end: new Date(start).toISOString() })
    }
    cursor = Math.max(cursor, end)
  }
  if (cursor < dayEnd.getTime()) {
    free.push({ start: new Date(cursor).toISOString(), end: dayEnd.toISOString() })
  }
  return { busy, free }
}

function GoogleAgendaAnnonceSection(props: {
  dossier: Dossier | null
  detail: DossierDetailPayload
  contacts: DetailContact[]
  canManageContacts?: boolean
  hektorUserEmail?: string | null
  hektorUserId?: string | null
  hektorNegotiators?: HektorNegotiatorOption[]
  profileRole?: UserProfile['role'] | null
  sessionEmail?: string | null
  onOpenContact?: (contactId: string) => void
  onHektorActionJobCreated?: (job: ConsoleJob) => void
}) {
  const dossier = props.dossier
  const appDossierId = dossier?.app_dossier_id ?? null
  const hektorAnnonceId = dossier?.hektor_annonce_id ?? null
  const defaultCalendarEmail = safeText(props.detail.appointment_negociateur_email) || safeText(dossier?.negociateur_email)
  const defaultLocation = [
    safeText(props.detail.adresse_privee_listing) || safeText(props.detail.adresse_detail),
    safeText(props.detail.code_postal_public_listing) || safeText(props.detail.code_postal_detail) || safeText(dossier?.code_postal),
    safeText(props.detail.ville_publique_listing) || safeText(props.detail.ville_privee_detail) || safeText(dossier?.ville),
  ].filter(Boolean).join(' ')
  const [calendarEmail, setCalendarEmail] = useState(defaultCalendarEmail)
  const [eventType, setEventType] = useState<GoogleCalendarEventLink['event_type']>('visite')
  const [summary, setSummary] = useState('')
  const [startAt, setStartAt] = useState(defaultGoogleAgendaStartValue)
  const [durationMinutes, setDurationMinutes] = useState('60')
  const [location, setLocation] = useState(defaultLocation)
  const [attendeesText, setAttendeesText] = useState('')
  const [attendeeContactLinks, setAttendeeContactLinks] = useState<GoogleAgendaInviteeContactLink[]>([])
  const [description, setDescription] = useState('')
  const [events, setEvents] = useState<GoogleCalendarEventLink[]>([])
  const [modalOpen, setModalOpen] = useState(false)
  const [agendaDate, setAgendaDate] = useState(dateInputFromDateTimeLocal(defaultGoogleAgendaStartValue()))
  const [agendaMode, setAgendaMode] = useState<GoogleAgendaViewMode>('day')
  const [dayAvailabilityPending, setDayAvailabilityPending] = useState(false)
  const [dayAvailability, setDayAvailability] = useState<GoogleCalendarAvailability | null>(null)
  const [periodLinkedEvents, setPeriodLinkedEvents] = useState<GoogleCalendarEventLink[]>([])
  const [contactSearch, setContactSearch] = useState('')
  const [contactOptions, setContactOptions] = useState<MandantContactSearchOption[]>([])
  const [contactSearchLoading, setContactSearchLoading] = useState(false)
  const [contactSearchError, setContactSearchError] = useState<string | null>(null)
  const [linkedRelationContactOptions, setLinkedRelationContactOptions] = useState<AnnonceContactInviteeOption[]>([])
  const [linkedRelationContactsLoading, setLinkedRelationContactsLoading] = useState(false)
  const [linkedRelationContactsError, setLinkedRelationContactsError] = useState<string | null>(null)
  const [contactCreateOpen, setContactCreateOpen] = useState(false)
  const [loading, setLoading] = useState(false)
  const [pending, setPending] = useState(false)
  const [availabilityPending, setAvailabilityPending] = useState(false)
  const [availability, setAvailability] = useState<GoogleCalendarAvailability | null>(null)
  const [editingEventId, setEditingEventId] = useState<string | null>(null)
  const [deletingId, setDeletingId] = useState<string | null>(null)
  const [printingId, setPrintingId] = useState<string | null>(null)
  const [message, setMessage] = useState<string | null>(null)
  const [error, setError] = useState<string | null>(null)

  useEffect(() => {
    if (editingEventId) return
    setCalendarEmail(defaultCalendarEmail)
  }, [defaultCalendarEmail, editingEventId])

  useEffect(() => {
    if (editingEventId) return
    setLocation(defaultLocation)
  }, [defaultLocation, editingEventId])

  useEffect(() => {
    if (editingEventId) return
    const title = dossier?.titre_bien || dossier?.numero_dossier || (dossier?.hektor_annonce_id ? `Annonce ${dossier.hektor_annonce_id}` : 'Annonce GTI')
    const label = googleAgendaEventTypeOptions.find((option) => option.value === eventType)?.label ?? 'RDV'
    setSummary(`${label} GTI - ${title}`)
  }, [dossier?.hektor_annonce_id, dossier?.numero_dossier, dossier?.titre_bien, editingEventId, eventType])

  useEffect(() => {
    if (editingEventId) return
    const title = dossier?.titre_bien || dossier?.numero_dossier || `Annonce ${dossier?.hektor_annonce_id ?? ''}`.trim()
    setDescription([
      'RDV cree depuis GTI.',
      title ? `Bien : ${title}` : '',
      dossier?.hektor_annonce_id ? `Annonce Hektor : ${dossier.hektor_annonce_id}` : '',
      dossier?.numero_dossier ? `Dossier : ${dossier.numero_dossier}` : '',
      dossier?.numero_mandat ? `Mandat : ${dossier.numero_mandat}` : '',
    ].filter(Boolean).join('\n'))
  }, [dossier?.hektor_annonce_id, dossier?.numero_dossier, dossier?.numero_mandat, dossier?.titre_bien, editingEventId])

  useEffect(() => {
    setEditingEventId(null)
  }, [appDossierId, hektorAnnonceId])

  useEffect(() => {
    setAvailability(null)
  }, [calendarEmail, durationMinutes, startAt])

  useEffect(() => {
    setAgendaDate(dateInputFromDateTimeLocal(startAt))
  }, [startAt])

  useEffect(() => {
    setDayAvailability(null)
    setPeriodLinkedEvents([])
  }, [agendaMode, calendarEmail])

  useEffect(() => {
    if (!modalOpen) return
    const search = contactSearch.trim()
    const scopedCalendarEmail = calendarEmail.trim().toLowerCase()
    const hektorContactSearchOwner = findContactHektorOption(props.hektorNegotiators ?? [], {
      idUser: dossier?.commercial_id,
      email: dossier?.negociateur_email || scopedCalendarEmail,
    })
    const contactSearchNegotiatorEmail = normalizeEmail(hektorContactSearchOwner?.email)
      || normalizeEmail(dossier?.negociateur_email)
      || scopedCalendarEmail
    const contactSearchAgencyName = (hektorContactSearchOwner?.agenceNom || dossier?.agence_nom || '').trim()
    const contactScope = contactSearchAgencyName
      ? { agencyName: contactSearchAgencyName, negotiatorEmail: contactSearchNegotiatorEmail || null }
      : contactSearchNegotiatorEmail.endsWith(`@${googleWorkspaceDomain}`)
        ? { negotiatorEmail: contactSearchNegotiatorEmail }
        : null
    const minSearchLength = /^\d+$/.test(search) ? 1 : 3
    if (search.length < minSearchLength) {
      setContactOptions([])
      setContactSearchLoading(false)
      setContactSearchError(null)
      return
    }
    let cancelled = false
    setContactSearchLoading(true)
    setContactSearchError(null)
    const handle = window.setTimeout(async () => {
      try {
        const rows = await searchMandantContactOptions({ search, scope: contactScope, limit: 8 })
        if (cancelled) return
        setContactOptions(rows)
      } catch (searchError) {
        if (cancelled) return
        setContactOptions([])
        setContactSearchError(searchError instanceof Error ? searchError.message : 'Recherche contact impossible.')
      } finally {
        if (!cancelled) setContactSearchLoading(false)
      }
    }, 260)
    return () => {
      cancelled = true
      window.clearTimeout(handle)
    }
  }, [calendarEmail, contactSearch, dossier?.agence_nom, dossier?.commercial_id, dossier?.negociateur_email, modalOpen, props.hektorNegotiators])

  useEffect(() => {
    if (!modalOpen || (!appDossierId && !hektorAnnonceId)) {
      setLinkedRelationContactOptions([])
      setLinkedRelationContactsLoading(false)
      setLinkedRelationContactsError(null)
      return
    }
    let cancelled = false
    setLinkedRelationContactsLoading(true)
    setLinkedRelationContactsError(null)
    void loadAnnonceContactInvitees({ appDossierId, hektorAnnonceId, limit: 24 })
      .then((rows) => {
        if (!cancelled) setLinkedRelationContactOptions(rows)
      })
      .catch((relationError) => {
        if (cancelled) return
        setLinkedRelationContactOptions([])
        setLinkedRelationContactsError(relationError instanceof Error ? relationError.message : 'Contacts lies impossibles a charger.')
      })
      .finally(() => {
        if (!cancelled) setLinkedRelationContactsLoading(false)
      })
    return () => {
      cancelled = true
    }
  }, [appDossierId, hektorAnnonceId, modalOpen])

  const canUseCalendarEmail = calendarEmail.trim().toLowerCase().endsWith(`@${googleWorkspaceDomain}`)
  const activeEvents = events.filter((item) => item.status !== 'deleted')
  const linkedAgendaContacts = useMemo(() => {
    const contactsByKey = new Map<string, GoogleAgendaLinkedInviteeOption>()
    const addContact = (item: Omit<GoogleAgendaLinkedInviteeOption, 'key'>) => {
      const hektorContactId = safeText(item.hektorContactId)
      const email = safeText(item.email).toLowerCase()
      const key = hektorContactId ? `contact-${hektorContactId}` : email ? `email-${email}` : `label-${item.label}-${contactsByKey.size}`
      const link = item.link ?? (email ? {
        email,
        label: item.label,
        hektorContactId: hektorContactId || null,
        source: 'annonce_contact',
      } : null)
      const next = { ...item, key, email, hektorContactId: hektorContactId || null, link }
      const existing = contactsByKey.get(key)
      if (!existing || (!existing.email && next.email)) contactsByKey.set(key, next)
    }

    props.contacts.forEach((contact) => {
      const email = detailContactAgendaEmail(contact)
      const contactId = detailContactDirectoryId(contact)
      addContact({
        label: detailContactAgendaLabel(contact),
        email,
        meta: email || contact.phone || 'Email absent',
        hektorContactId: contactId,
        link: detailContactAgendaLink(contact, email),
      })
    })

    linkedRelationContactOptions.forEach((option) => {
      const email = contactOptionAgendaEmail(option)
      const relationLabel = googleAgendaRelationRoleLabel(option.role_contact)
      const secondary = email || option.phone_primary || option.phone_secondary || 'Email absent'
      addContact({
        label: mandantContactOptionTitle(option),
        email,
        meta: `${relationLabel} - ${secondary}`,
        hektorContactId: option.hektor_contact_id,
        link: contactOptionAgendaLink(option, email),
      })
    })

    return Array.from(contactsByKey.values())
  }, [linkedRelationContactOptions, props.contacts])
  const isEditingGoogleAgendaEvent = Boolean(editingEventId)
  const hasCustomDuration = durationMinutes && !googleAgendaDurationOptions.includes(durationMinutes)
  const availabilityBusy = availability?.busy ?? []
  const canCheckAvailability = canUseCalendarEmail && Boolean(startAt) && Boolean(durationMinutes)
  const agendaPeriodDays = googleAgendaPeriodDays(agendaDate, agendaMode)
  const periodEvents = mergeGoogleCalendarEventLinks([...periodLinkedEvents, ...activeEvents])
  const agendaDayPlans = agendaPeriodDays.map((day) => ({
    day,
    label: googleAgendaDayLabel(day),
    events: googleAgendaEventsForDay(periodEvents, day),
    ...buildGoogleAgendaDayWindows(day, dayAvailability),
  }))
  const requestedDurationMinutes = Number(durationMinutes)
  const suggestedWindows = buildGoogleAgendaSuggestedWindows(agendaDayPlans.flatMap((day) => day.free), requestedDurationMinutes, 5)
  const nextLinkedEvent = activeEvents
    .filter((item) => new Date(item.starts_at).getTime() >= Date.now())
    .sort((left, right) => new Date(left.starts_at).getTime() - new Date(right.starts_at).getTime())[0]

  const reloadEvents = useCallback(async () => {
    if (!appDossierId && !hektorAnnonceId) return
    setLoading(true)
    setError(null)
    try {
      const rows = await loadGoogleCalendarEventLinks({
        appDossierId,
        hektorAnnonceId,
        limit: 25,
      })
      setEvents(rows)
    } catch (eventError) {
      setError(eventError instanceof Error ? eventError.message : 'Chargement Agenda Google impossible')
    } finally {
      setLoading(false)
    }
  }, [appDossierId, hektorAnnonceId])

  useEffect(() => {
    void reloadEvents()
  }, [reloadEvents])

  function resetGoogleAgendaForm() {
    setEditingEventId(null)
    setEventType('visite')
    setStartAt(defaultGoogleAgendaStartValue())
    setDurationMinutes('60')
    setLocation(defaultLocation)
    setAttendeesText('')
    setAttendeeContactLinks([])
    setDescription('')
    setAvailability(null)
  }

  function handleEditGoogleAgendaEvent(link: GoogleCalendarEventLink) {
    const nextStartAt = toExistingDateTimeLocalValue(link.starts_at, defaultGoogleAgendaStartValue())
    setEditingEventId(link.id)
    setCalendarEmail(link.google_calendar_email)
    setEventType(link.event_type)
    setSummary(link.summary)
    setStartAt(nextStartAt)
    setDurationMinutes(minutesBetweenDateTimes(link.starts_at, link.ends_at))
    setLocation(link.location ?? '')
    const nextAttendees = Array.isArray(link.attendees_json) ? link.attendees_json : []
    setAttendeesText(nextAttendees.join(', '))
    setAttendeeContactLinks(mergeGoogleAgendaInviteeContactLinks([], googleAgendaEventInviteeContacts(link), nextAttendees))
    setDescription('')
    setAvailability(null)
    setMessage(null)
    setError(null)
  }

  async function handleCheckGoogleAgendaAvailability() {
    setAvailabilityPending(true)
    setAvailability(null)
    setMessage(null)
    setError(null)
    try {
      const minutes = Number(durationMinutes)
      const endAt = addMinutesToDateTimeLocal(startAt, Number.isFinite(minutes) ? minutes : 60)
      if (!endAt) throw new Error('Horaire RDV invalide')
      const result = await checkGoogleCalendarAvailability({
        subjectEmail: calendarEmail,
        startAt,
        endAt,
      })
      if (!result.ok) throw new Error('Verification disponibilite Google impossible')
      setAvailability(result)
    } catch (eventError) {
      setError(eventError instanceof Error ? eventError.message : 'Verification disponibilite Google impossible')
    } finally {
      setAvailabilityPending(false)
    }
  }

  async function handleLoadGoogleAgendaPeriod(dayValue = agendaDate, mode = agendaMode) {
    setDayAvailabilityPending(true)
    setDayAvailability(null)
    setPeriodLinkedEvents([])
    setError(null)
    try {
      if (!canUseCalendarEmail) throw new Error('Agenda Google Workspace requis')
      const range = googleAgendaPeriodRange(dayValue, mode)
      const result = await checkGoogleCalendarAvailability({
        subjectEmail: calendarEmail,
        startAt: range.startAt,
        endAt: range.endAt,
      })
      if (!result.ok) throw new Error('Chargement occupation agenda impossible')
      setDayAvailability(result)
      try {
        const rows = await loadGoogleCalendarEventLinks({
          calendarEmail,
          limit: 100,
        })
        setPeriodLinkedEvents(rows)
      } catch {
        setPeriodLinkedEvents([])
      }
    } catch (eventError) {
      setError(eventError instanceof Error ? eventError.message : 'Chargement occupation agenda impossible')
    } finally {
      setDayAvailabilityPending(false)
    }
  }

  function handleOpenGoogleAgendaModal() {
    const nextDate = dateInputFromDateTimeLocal(startAt)
    setAgendaDate(nextDate)
    setModalOpen(true)
    void reloadEvents()
    if (canUseCalendarEmail) {
      void handleLoadGoogleAgendaPeriod(nextDate, agendaMode)
    }
  }

  function handleCloseGoogleAgendaModal() {
    setModalOpen(false)
  }

  function handleUseGoogleAgendaWindow(window: GoogleAgendaWindow) {
    const windowMinutes = minutesBetweenWindow(window)
    const requestedMinutes = Number(durationMinutes)
    setStartAt(toDateTimeLocalValue(new Date(window.start)))
    if (Number.isFinite(requestedMinutes) && requestedMinutes > windowMinutes) {
      setDurationMinutes(String(windowMinutes))
    }
    setAvailability(null)
  }

  function handleAttendeesTextChange(value: string) {
    setAttendeesText(value)
    setAttendeeContactLinks((current) => mergeGoogleAgendaInviteeContactLinks(current, [], splitEmailList(value)))
  }

  function handleAddAgendaInvitee(link: GoogleAgendaInviteeContactLink | string) {
    const normalized = typeof link === 'string'
      ? normalizeGoogleAgendaInviteeContactLink({ email: link })
      : normalizeGoogleAgendaInviteeContactLink(link)
    if (!normalized) return
    const nextText = joinEmailList([...splitEmailList(attendeesText), normalized.email])
    const nextAttendees = splitEmailList(nextText)
    setAttendeesText(nextText)
    setAttendeeContactLinks((current) => mergeGoogleAgendaInviteeContactLinks(current, [normalized], nextAttendees))
  }

  function handleRemoveAgendaInvitee(email: string) {
    const cleanEmail = email.trim().toLowerCase()
    const nextText = joinEmailList(splitEmailList(attendeesText).filter((item) => item !== cleanEmail))
    const nextAttendees = splitEmailList(nextText)
    setAttendeesText(nextText)
    setAttendeeContactLinks((current) => mergeGoogleAgendaInviteeContactLinks(current, [], nextAttendees))
  }

  function handleGoogleAgendaContactJobCreated(contact: HektorContactIdentityInput) {
    const createdEmail = hektorContactInputAgendaEmail(contact)
    if (createdEmail) {
      handleAddAgendaInvitee({
        email: createdEmail,
        label: contactInputAgendaLabel(contact),
        source: 'contact_create_pending',
      })
    }
    setContactCreateOpen(false)
    setMessage(createdEmail ? 'Contact envoye au worker et ajoute aux invites.' : 'Contact envoye au worker.')
  }

  async function handleSubmitGoogleAgendaEvent(event: FormEvent<HTMLFormElement>) {
    event.preventDefault()
    if (!dossier) return
    setPending(true)
    setMessage(null)
    setError(null)
    try {
      const minutes = Number(durationMinutes)
      const endAt = addMinutesToDateTimeLocal(startAt, Number.isFinite(minutes) ? minutes : 60)
      if (!endAt) throw new Error('Horaire RDV invalide')
      const attendees = splitEmailList(attendeesText)
      const attendeeContacts = googleAgendaInviteeContactMetadata(attendeeContactLinks, attendees)
      if (editingEventId) {
        await updateGoogleCalendarEvent(editingEventId, {
          summary,
          startAt,
          endAt,
          description: description.trim() ? description : undefined,
          location,
          attendees,
          metadata: {
            attendee_contacts: attendeeContacts,
            attendee_contact_count: attendeeContacts.length,
          },
          sendUpdates: 'all',
        })
        resetGoogleAgendaForm()
        setMessage('RDV Google modifie.')
      } else {
        await createGoogleCalendarEvent({
          subjectEmail: calendarEmail,
          eventType,
          relatedEntityType: 'annonce',
          relatedEntityId: String(dossier.app_dossier_id),
          appDossierId: dossier.app_dossier_id,
          hektorAnnonceId: dossier.hektor_annonce_id,
          summary,
          startAt,
          endAt,
          description,
          location,
          attendees,
          sendUpdates: 'all',
          metadata: {
            source: 'fiche_annonce',
            numero_dossier: dossier.numero_dossier,
            numero_mandat: dossier.numero_mandat,
            attendee_contacts: attendeeContacts,
            attendee_contact_count: attendeeContacts.length,
          },
        })
        setMessage('RDV Google cree.')
        setAttendeesText('')
        setAttendeeContactLinks([])
      }
      setAvailability(null)
      await reloadEvents()
    } catch (eventError) {
      setError(eventError instanceof Error ? eventError.message : 'Enregistrement RDV Google impossible')
    } finally {
      setPending(false)
    }
  }

  async function handleDeleteGoogleAgendaEvent(link: GoogleCalendarEventLink) {
    if (!window.confirm(`Supprimer ce RDV Google : ${link.summary} ?`)) return
    setDeletingId(link.id)
    setMessage(null)
    setError(null)
    try {
      await deleteGoogleCalendarEvent(link.id, { sendUpdates: 'all' })
      setMessage('RDV Google supprime.')
      await reloadEvents()
    } catch (eventError) {
      setError(eventError instanceof Error ? eventError.message : 'Suppression RDV Google impossible')
    } finally {
      setDeletingId(null)
    }
  }

  async function handlePrintGoogleAgendaVisitVoucher(link: GoogleCalendarEventLink) {
    if (!dossier) return
    const voucherContact = visitVoucherContactFromAnnonceEvent(link, props.contacts)
    const voucherRelations = visitVoucherRelationsFromDossier(dossier)
    const printWindow = window.open('', '_blank')
    writeVisitVoucherWindow(printWindow, visitVoucherLoadingHtml())
    setPrintingId(link.id)
    setMessage(null)
    setError(null)
    let photoUrl: string | null = null
    try {
      photoUrl = await loadVisitVoucherPhotoUrl(link, voucherRelations)
    } catch (photoError) {
      console.warn('Visit voucher photo loading failed', photoError)
    } finally {
      openVisitVoucherPrint(voucherContact, link, voucherRelations, photoUrl, printWindow)
      setPrintingId(null)
    }
  }

  return (
    <section className="detail-section detail-google-agenda-section">
      <div className="section-header">
        <DetailSectionTitle icon="commercial" title="Agenda Google" />
        {loading ? <span>Chargement...</span> : null}
      </div>
      <article className="detail-card google-agenda-entry-card">
        <div>
          <span className="detail-label">Rendez-vous Google</span>
          <div className="info-grid">
            <InfoCard label="Agenda" value={calendarEmail || '-'} />
            <InfoCard label="RDV lies" value={String(activeEvents.length)} />
            <InfoCard label="Prochain RDV" value={nextLinkedEvent ? formatDateTime(nextLinkedEvent.starts_at) : '-'} />
          </div>
        </div>
        <div className="google-agenda-entry-actions">
          {!canUseCalendarEmail ? <p className="google-agenda-error">Agenda Google Workspace requis.</p> : null}
          <button className="ghost-button button-primary" type="button" onClick={handleOpenGoogleAgendaModal}>
            Ouvrir les RDV Google
          </button>
        </div>
      </article>
      {modalOpen && typeof document !== 'undefined' ? createPortal(
        <div className="modal-overlay google-agenda-modal-overlay" onClick={handleCloseGoogleAgendaModal}>
          <section className="modal-panel google-agenda-modal" onClick={(event) => event.stopPropagation()}>
            <div className="google-agenda-modal-head">
              <div>
                <span className="eyebrow">Google Agenda</span>
                <h3>Rendez-vous Google</h3>
                <p>{dossier?.titre_bien || dossier?.numero_dossier || 'Annonce GTI'}</p>
              </div>
              <button className="request-modal-close" type="button" onClick={handleCloseGoogleAgendaModal}>Fermer</button>
            </div>
            <div className="google-agenda-modal-meta">
              <span><strong>Agenda</strong>{calendarEmail || '-'}</span>
              <span><strong>Commercial</strong>{dossier?.commercial_nom || '-'}</span>
              <span><strong>Mandat</strong>{dossier?.numero_mandat || '-'}</span>
              <span><strong>RDV lies</strong>{activeEvents.length}</span>
            </div>
            <div className="google-agenda-modal-layout">
              <section className="google-agenda-panel google-agenda-planner-panel">
                <div className="google-agenda-panel-head">
                  <span>{isEditingGoogleAgendaEvent ? 'Modification' : 'Creation'}</span>
                  <strong>{isEditingGoogleAgendaEvent ? 'Modifier le RDV' : 'Planifier un RDV'}</strong>
                </div>
                <form className="google-agenda-form" onSubmit={handleSubmitGoogleAgendaEvent}>
                  <label className="filter-field">
                    <span>Agenda</span>
                    <input value={calendarEmail} onChange={(inputEvent) => setCalendarEmail(inputEvent.target.value)} type="email" placeholder={`nego@${googleWorkspaceDomain}`} required disabled={isEditingGoogleAgendaEvent} />
                  </label>
                  <label className="filter-field">
                    <span>Type</span>
                    <select value={eventType} onChange={(inputEvent) => setEventType(inputEvent.target.value as GoogleCalendarEventLink['event_type'])}>
                      {googleAgendaEventTypeOptions.map((option) => (
                        <option key={option.value} value={option.value}>{option.label}</option>
                      ))}
                    </select>
                  </label>
                  <label className="filter-field google-agenda-field-wide">
                    <span>Titre</span>
                    <input value={summary} onChange={(inputEvent) => setSummary(inputEvent.target.value)} required />
                  </label>
                  <label className="filter-field">
                    <span>Debut</span>
                    <input value={startAt} onChange={(inputEvent) => setStartAt(inputEvent.target.value)} type="datetime-local" required />
                  </label>
                  <label className="filter-field">
                    <span>Duree</span>
                    <select value={durationMinutes} onChange={(inputEvent) => setDurationMinutes(inputEvent.target.value)}>
                      {hasCustomDuration ? <option value={durationMinutes}>{durationMinutes} min</option> : null}
                      <option value="30">30 min</option>
                      <option value="45">45 min</option>
                      <option value="60">1 h</option>
                      <option value="90">1 h 30</option>
                      <option value="120">2 h</option>
                    </select>
                  </label>
                  <label className="filter-field google-agenda-field-wide">
                    <span>Lieu</span>
                    <input value={location} onChange={(inputEvent) => setLocation(inputEvent.target.value)} />
                  </label>
                  <label className="filter-field google-agenda-field-wide">
                    <span>Invites</span>
                    <input value={attendeesText} onChange={(inputEvent) => handleAttendeesTextChange(inputEvent.target.value)} placeholder="client@email.fr" />
                  </label>
                  <div className="google-agenda-field-wide google-agenda-invitees">
                    <div className="google-agenda-invitee-selected">
                      <span className="detail-label">Invites selectionnes</span>
                      {splitEmailList(attendeesText).length > 0 ? (
                        <div className="google-agenda-invitee-chip-row">
                          {splitEmailList(attendeesText).map((email) => {
                            const contactLink = attendeeContactLinks.find((item) => item.email === email)
                            return (
                              <button key={`invitee-${email}`} className={`google-agenda-invitee-chip${contactLink?.hektorContactId ? ' is-linked' : ''}`} type="button" onClick={() => handleRemoveAgendaInvitee(email)}>
                                <strong>{contactLink?.label || email}</strong>
                                <small>{contactLink?.hektorContactId ? `Contact ${contactLink.hektorContactId}` : email}</small>
                                <span aria-hidden="true">x</span>
                              </button>
                            )
                          })}
                        </div>
                      ) : <p className="empty-state">Aucun invite ajoute.</p>}
                    </div>
                    <div className="google-agenda-invitee-tools">
                      <div>
                        <span className="detail-label">Contacts lies a l'annonce</span>
                        {linkedRelationContactsLoading ? <p className="empty-state">Chargement contacts lies...</p> : null}
                        {linkedRelationContactsError ? <p className="google-agenda-error">{linkedRelationContactsError}</p> : null}
                        {linkedAgendaContacts.length > 0 ? (
                          <div className="google-agenda-contact-list">
                            {linkedAgendaContacts.map((option) => {
                              return (
                                <button key={`linked-contact-${option.key}`} className="google-agenda-contact-button" type="button" onClick={() => option.link && handleAddAgendaInvitee(option.link)} disabled={!option.link}>
                                  <strong>{option.label}</strong>
                                  <span>{option.meta}</span>
                                  {option.hektorContactId ? <small>Contact {option.hektorContactId}</small> : <small>{option.email ? 'Email direct' : 'Email absent'}</small>}
                                </button>
                              )
                            })}
                          </div>
                        ) : !linkedRelationContactsLoading ? <p className="empty-state">Aucun contact lie trouve.</p> : null}
                      </div>
                      <div>
                        <span className="detail-label">Recherche etendue</span>
                        <div className="google-agenda-contact-search">
                          <input value={contactSearch} onChange={(inputEvent) => setContactSearch(inputEvent.target.value)} placeholder="Nom, email, telephone..." />
                          {props.canManageContacts ? (
                            <button className="ghost-button button-subtle" type="button" onClick={() => setContactCreateOpen(true)}>
                              Nouveau contact
                            </button>
                          ) : null}
                        </div>
                        {contactSearchLoading ? <p className="empty-state">Recherche contacts...</p> : null}
                        {contactSearchError ? <p className="google-agenda-error">{contactSearchError}</p> : null}
                        {contactSearch.trim().length > 0 && contactSearch.trim().length < (/^\d+$/.test(contactSearch.trim()) ? 1 : 3) ? <p className="empty-state">Saisis au moins 3 caracteres pour lancer la recherche.</p> : null}
                        {contactOptions.length > 0 ? (
                          <div className="google-agenda-contact-list">
                            {contactOptions.map((option) => {
                              const email = contactOptionAgendaEmail(option)
                              const contactLink = contactOptionAgendaLink(option, email)
                              return (
                                <button key={`contact-option-${option.hektor_contact_id}`} className="google-agenda-contact-button" type="button" onClick={() => contactLink && handleAddAgendaInvitee(contactLink)} disabled={!contactLink}>
                                  <strong>{mandantContactOptionTitle(option)}</strong>
                                  <span>{email || option.phone_primary || option.phone_secondary || 'Email absent'}</span>
                                  <small>{mandantContactOptionSubtitle(option)}</small>
                                </button>
                              )
                            })}
                          </div>
                        ) : contactSearch.trim().length >= (/^\d+$/.test(contactSearch.trim()) ? 1 : 3) && !contactSearchLoading ? <p className="empty-state">Aucun contact trouve dans le perimetre agence/negociateur.</p> : null}
                      </div>
                    </div>
                  </div>
                  <label className="filter-field google-agenda-field-wide">
                    <span>Description</span>
                    <textarea className="inline-textarea" value={description} onChange={(inputEvent) => setDescription(inputEvent.target.value)} placeholder={isEditingGoogleAgendaEvent ? 'Vide = description Google conservee' : undefined} />
                  </label>
                  {!canUseCalendarEmail ? <p className="google-agenda-error">Agenda Google Workspace requis.</p> : null}
                  {message ? <p className="google-agenda-success">{message}</p> : null}
                  {error ? <p className="google-agenda-error">{error}</p> : null}
                  {availability ? (
                    <div className={availability.isAvailable ? 'google-agenda-success' : 'google-agenda-warning'}>
                      <strong>{availability.isAvailable ? 'Disponible sur ce creneau.' : `Conflit agenda : ${availability.busyCount ?? availabilityBusy.length} creneau occupe.`}</strong>
                      {!availability.isAvailable && availabilityBusy.length > 0 ? (
                        <span>{availabilityBusy.slice(0, 3).map((slot) => `${formatDateTime(slot.start)} - ${formatDateTime(slot.end)}`).join(' | ')}</span>
                      ) : null}
                    </div>
                  ) : null}
                  <div className="modal-actions google-agenda-actions">
                    {isEditingGoogleAgendaEvent ? (
                      <button className="ghost-button button-subtle" type="button" onClick={resetGoogleAgendaForm} disabled={pending}>
                        Annuler
                      </button>
                    ) : null}
                    <button className="ghost-button button-subtle" type="button" onClick={() => void handleCheckGoogleAgendaAvailability()} disabled={availabilityPending || pending || !canCheckAvailability}>
                      {availabilityPending ? 'Verification...' : 'Verifier dispo'}
                    </button>
                    <button className="ghost-button button-primary" type="submit" disabled={pending || !canUseCalendarEmail || !summary.trim()}>
                      {pending ? (isEditingGoogleAgendaEvent ? 'Enregistrement...' : 'Creation...') : isEditingGoogleAgendaEvent ? 'Enregistrer le RDV' : 'Creer RDV Google'}
                    </button>
                  </div>
                </form>
              </section>
              <section className="google-agenda-panel google-agenda-day-panel">
                <div className="google-agenda-panel-head google-agenda-day-head">
                  <div>
                    <span>Agenda negociateur</span>
                    <strong>{agendaMode === 'week' ? 'Occupation semaine' : 'Occupation journee'}</strong>
                    <small>{googleAgendaRangeLabel(agendaDate, agendaMode)}</small>
                  </div>
                  <div className="google-agenda-day-actions">
                    <div className="google-agenda-view-toggle" role="group" aria-label="Vue agenda">
                      <button className={agendaMode === 'day' ? 'is-active' : ''} type="button" onClick={() => { setAgendaMode('day'); setDayAvailability(null); setPeriodLinkedEvents([]) }}>
                        Jour
                      </button>
                      <button className={agendaMode === 'week' ? 'is-active' : ''} type="button" onClick={() => { setAgendaMode('week'); setDayAvailability(null); setPeriodLinkedEvents([]) }}>
                        Semaine
                      </button>
                    </div>
                    <input value={agendaDate} onChange={(inputEvent) => { setAgendaDate(inputEvent.target.value); setDayAvailability(null); setPeriodLinkedEvents([]) }} type="date" />
                    <button className="ghost-button button-subtle" type="button" onClick={() => void handleLoadGoogleAgendaPeriod()} disabled={dayAvailabilityPending || !canUseCalendarEmail}>
                      {dayAvailabilityPending ? 'Chargement...' : 'Actualiser'}
                    </button>
                  </div>
                </div>
                {dayAvailability ? (
                  <>
                    <div className="google-agenda-suggestions">
                      <span className="detail-label">{agendaMode === 'week' ? 'Creneaux proposes sur la semaine' : 'Creneaux proposes'}</span>
                      {suggestedWindows.length > 0 ? (
                        <div className="google-agenda-suggestion-list">
                          {suggestedWindows.map((slot, index) => (
                            <button key={`suggestion-${slot.start}-${slot.end}`} className="google-agenda-suggestion" type="button" onClick={() => handleUseGoogleAgendaWindow(slot)}>
                              <strong>{index === 0 ? 'Meilleur creneau' : `Option ${index + 1}`}</strong>
                              <span>{formatDateTime(slot.start)} - {formatDateTime(slot.end)}</span>
                            </button>
                          ))}
                        </div>
                      ) : <p className="empty-state">Aucun creneau assez long pour la duree choisie.</p>}
                    </div>
                    <div className={`google-agenda-period-grid is-${agendaMode}`}>
                      {agendaDayPlans.map((plan) => (
                        <article key={`agenda-period-${plan.day}`} className="google-agenda-period-day">
                          <div className="google-agenda-period-day-head">
                            <strong>{plan.label}</strong>
                            <span>{plan.events.length} RDV GTI - {plan.busy.length} occupe</span>
                          </div>
                          <div className="google-agenda-period-section">
                            <span className="detail-label">RDV GTI</span>
                            {plan.events.length > 0 ? (
                              <div className="google-agenda-period-items">
                                {plan.events.map((item) => (
                                  <button key={`period-gti-${plan.day}-${item.id}`} className="google-agenda-period-event" type="button" onClick={() => handleEditGoogleAgendaEvent(item)}>
                                    <strong>{formatDateTime(item.starts_at)} - {formatDateTime(item.ends_at)}</strong>
                                    <span>{item.summary}</span>
                                  </button>
                                ))}
                              </div>
                            ) : <p className="empty-state">Aucun RDV GTI lie.</p>}
                          </div>
                          <div className="google-agenda-period-section">
                            <span className="detail-label">Google occupe</span>
                            <div className="google-agenda-day-slots">
                              {plan.busy.length > 0 ? plan.busy.map((slot) => (
                                <article key={`busy-${plan.day}-${slot.start}-${slot.end}`} className="google-agenda-day-slot is-busy">
                                  <strong>{formatDateTime(slot.start)} - {formatDateTime(slot.end)}</strong>
                                  <span>Occupe Google</span>
                                </article>
                              )) : <p className="empty-state">Aucun creneau occupe.</p>}
                            </div>
                          </div>
                          <div className="google-agenda-period-section">
                            <span className="detail-label">Libres</span>
                            <div className="google-agenda-day-slots">
                              {plan.free.length > 0 ? plan.free.map((slot) => (
                                <article key={`free-${plan.day}-${slot.start}-${slot.end}`} className="google-agenda-day-slot is-free">
                                  <div>
                                    <strong>{formatDateTime(slot.start)} - {formatDateTime(slot.end)}</strong>
                                    <span>{minutesBetweenWindow(slot)} min libres</span>
                                  </div>
                                  <button className="ghost-button button-subtle" type="button" onClick={() => handleUseGoogleAgendaWindow(slot)}>
                                    Utiliser
                                  </button>
                                </article>
                              )) : <p className="empty-state">Aucun creneau libre entre 08:00 et 19:00.</p>}
                            </div>
                          </div>
                        </article>
                      ))}
                    </div>
                  </>
                ) : <p className="empty-state">{dayAvailabilityPending ? 'Chargement agenda...' : 'Clique sur Actualiser pour voir les plages libres et occupees.'}</p>}
              </section>
              <section className="google-agenda-panel google-agenda-links-panel">
                <div className="google-agenda-panel-head">
                  <span>Annonce GTI</span>
                  <strong>RDV lies</strong>
                </div>
                {activeEvents.length > 0 ? (
                  <div className="google-agenda-event-list">
                    {activeEvents.map((item) => {
                      const eventInvitees = Array.isArray(item.attendees_json) ? item.attendees_json : []
                      const eventInviteeContacts = googleAgendaEventInviteeContacts(item)
                      return (
                        <article key={item.id} className="google-agenda-event-card">
                          <div>
                            <strong>{item.summary}</strong>
                            <span>{formatDateTime(item.starts_at)} - {formatDateTime(item.ends_at)}</span>
                            <span>{item.google_calendar_email}</span>
                            {item.location ? <span>{item.location}</span> : null}
                            {eventInvitees.length > 0 ? <span>Invites : {eventInvitees.join(', ')}</span> : null}
                            {eventInviteeContacts.length > 0 ? (
                              <div className="google-agenda-event-contact-row">
                                {eventInviteeContacts.map((contactLink) => contactLink.hektorContactId && props.onOpenContact ? (
                                  <button key={`event-contact-${item.id}-${contactLink.email}`} type="button" onClick={() => props.onOpenContact?.(contactLink.hektorContactId as string)}>
                                    <strong>{contactLink.label || contactLink.email}</strong>
                                    <span>Contact {contactLink.hektorContactId}</span>
                                  </button>
                                ) : (
                                  <span key={`event-contact-${item.id}-${contactLink.email}`}>{contactLink.label || contactLink.email}</span>
                                ))}
                              </div>
                            ) : null}
                          </div>
                          <div className="google-agenda-event-actions">
                            {item.google_html_link ? (
                              <a className="ghost-button button-subtle" href={item.google_html_link} target="_blank" rel="noreferrer">Ouvrir</a>
                            ) : null}
                            {canPrintVisitVoucher(item) ? (
                              <button className="ghost-button button-primary" type="button" onClick={() => void handlePrintGoogleAgendaVisitVoucher(item)} disabled={pending || deletingId === item.id || printingId === item.id}>
                                {printingId === item.id ? 'Preparation...' : 'Bon de visite'}
                              </button>
                            ) : null}
                            <button className="ghost-button button-subtle" type="button" onClick={() => handleEditGoogleAgendaEvent(item)} disabled={pending || deletingId === item.id}>
                              Modifier
                            </button>
                            <button className="ghost-button button-subtle" type="button" onClick={() => void handleDeleteGoogleAgendaEvent(item)} disabled={deletingId === item.id}>
                              {deletingId === item.id ? 'Suppression...' : 'Supprimer'}
                            </button>
                          </div>
                        </article>
                      )
                    })}
                  </div>
                ) : <p className="empty-state">{loading ? 'Chargement des RDV Google...' : 'Aucun RDV Google lie a cette annonce.'}</p>}
              </section>
            </div>
            {contactCreateOpen && props.canManageContacts ? (
              <ContactWorkflowModal
                title="Nouveau contact"
                eyebrow="Creation Hektor"
                summary="Creation via le workflow contact existant, puis ajout aux invites si un email est renseigne."
                tone="create"
                onClose={() => setContactCreateOpen(false)}
              >
                <HektorContactIdentityForm
                  mode="create"
                  hektorUserEmail={props.hektorUserEmail}
                  hektorUserId={props.hektorUserId}
                  hektorNegotiators={props.hektorNegotiators}
                  profileRole={props.profileRole}
                  sessionEmail={props.sessionEmail}
                  onCancel={() => setContactCreateOpen(false)}
                  onJobCreated={props.onHektorActionJobCreated}
                  onContactInputCreated={handleGoogleAgendaContactJobCreated}
                />
              </ContactWorkflowModal>
            ) : null}
          </section>
        </div>,
        document.body,
      ) : null}
    </section>
  )
}

function AppointmentAnnonceSection(props: {
  dossier: Dossier | null
  detail: DossierDetailPayload
}) {
  const appointmentUrl = buildAppointmentAnnonceUrl(props.dossier, props.detail)
  const requests = parseAppointmentRequests(props.detail)
  const events = parseAppointmentRequestEvents(props.detail)
  const appointmentEmail = safeText(props.detail.appointment_negociateur_email) || props.dossier?.negociateur_email || '-'
  const appointmentNegociateurId = props.detail.appointment_negociateur_id ?? props.dossier?.commercial_id ?? '-'

  return (
    <section className="detail-section detail-appointment-section">
      <div className="section-header"><DetailSectionTitle icon="contact" title="Rendez-vous annonce" /></div>
      <div className="detail-stack">
        <article className="detail-card">
          <span className="detail-label">Ciblage QR</span>
          <div className="info-grid">
            <InfoCard label="Mode" value="QR annonce vitrine" />
            <InfoCard label="ID annonce" value={props.dossier?.hektor_annonce_id ?? '-'} />
            <InfoCard label="Negociateur" value={props.dossier?.commercial_nom ?? '-'} />
            <InfoCard label="ID nego" value={appointmentNegociateurId} />
            <InfoCard label="Email nego" value={appointmentEmail} />
            <InfoCard label="Agence" value={props.dossier?.agence_nom ?? '-'} />
          </div>
          <div className="detail-rich-copy">
            <strong>URL publique cible</strong>
            <p>{appointmentUrl ?? 'Aucune URL publique configuree pour le moment.'}</p>
          </div>
        </article>
        <article className="detail-card">
          <span className="detail-label">Demandes recues</span>
          {requests.length > 0 ? (
            <div className="timeline-list">
              {requests.map((item, index) => (
                <article key={String(item.id ?? index)} className="timeline-card">
                  <strong>{item.client_nom ?? 'Client sans nom'} · {appointmentStatusLabel(item.status)}</strong>
                  <span>{formatDate(item.requested_start_at)}{item.requested_end_at ? ` → ${formatDate(item.requested_end_at)}` : ''}</span>
                  <span>{item.client_telephone ?? item.client_email ?? '-'}</span>
                  <p>{item.message ?? 'Sans message client.'}</p>
                </article>
              ))}
            </div>
          ) : <p className="empty-state">Aucune demande RDV stockee pour cette annonce pour le moment.</p>}
        </article>
        <article className="detail-card">
          <span className="detail-label">Historique RDV</span>
          {events.length > 0 ? (
            <div className="timeline-list">
              {events.map((item, index) => (
                <article key={String(item.id ?? index)} className="timeline-card">
                  <strong>{item.event_label ?? item.event_type ?? 'Evenement RDV'}</strong>
                  <span>{formatDate(item.created_at)}</span>
                  <span>{item.actor_name ?? 'Systeme'}</span>
                  <p>{item.payload_json ?? 'Sans detail supplementaire.'}</p>
                </article>
              ))}
            </div>
          ) : <p className="empty-state">Historique RDV vide tant que le module de demandes n'est pas encore stocke en base.</p>}
        </article>
      </div>
    </section>
  )
}

